INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('black-currant','Black Currant','Ribes nigrum','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','cutting','perennial','hardy','spring',0,3,'Plant hardwood cuttings or dormant bare-root stock in early spring, burying the cutting deeper than other Ribes to encourage multiple basal shoots.',3,6,48,60,36,60,36,60,'partial','moderate','Black currants fruit most heavily on one-year-old wood, so annual renewal pruning is critical: remove one-third of the oldest canes each late winter to stimulate vigorous new shoots. The berries have a strong, tannic flavor prized for jams and juices; harvest when the entire strig has turned glossy black. Choose blister-rust-resistant cultivars such as ''Consort'' or ''Titania'' where regulations permit. Verify local restrictions before planting.','["general horticultural reference", "university extension guides"]','{"slug": "black-currant", "common_name": "Black Currant", "scientific_name": "Ribes nigrum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Plant hardwood cuttings or dormant bare-root stock in early spring, burying the cutting deeper than other Ribes to encourage multiple basal shoots."}, "usda_zones": {"min": 3, "max": 6}, "spacing_in": {"min": 48, "max": 60}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 36, "max": 60}, "sun": "partial", "water": "moderate", "directions": "Black currants fruit most heavily on one-year-old wood, so annual renewal pruning is critical: remove one-third of the oldest canes each late winter to stimulate vigorous new shoots. The berries have a strong, tannic flavor prized for jams and juices; harvest when the entire strig has turned glossy black. Choose blister-rust-resistant cultivars such as ''Consort'' or ''Titania'' where regulations permit. Verify local restrictions before planting.", "sources": ["general horticultural reference", "university extension guides"]}')
