  VALUES ('blackberry','Blackberry','Rubus allegheniensis','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','hardy','spring',0,4,'Plant bare-root canes in early spring; trailing and semi-erect types need a trellis installed at planting.',5,10,36,60,36,96,36,72,'full','moderate','Blackberries fruit on second-year floricanes; remove all fruited canes at the base after harvest and thin new primocanes to 4–6 per hill. Erect types can be tip-pruned at 3–4 ft in midsummer to encourage lateral branching and larger yields. Harvest when berries are fully black, slightly soft, and the white core is not visible — they do not ripen further off the plant. Trailing cultivars require a T-trellis; thornless varieties are easier to manage but may be less cold-hardy.','["general horticultural reference", "university extension guides"]','{"slug": "blackberry", "common_name": "Blackberry", "scientific_name": "Rubus allegheniensis", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root canes in early spring; trailing and semi-erect types need a trellis installed at planting."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 36, "max": 96}, "spread_in": {"min": 36, "max": 72}, "sun": "full", "water": "moderate", "directions": "Blackberries fruit on second-year floricanes; remove all fruited canes at the base after harvest and thin new primocanes to 4–6 per hill. Erect types can be tip-pruned at 3–4 ft in midsummer to encourage lateral branching and larger yields. Harvest when berries are fully black, slightly soft, and the white core is not visible — they do not ripen further off the plant. Trailing cultivars require a T-trellis; thornless varieties are easier to manage but may be less cold-hardy.", "sources": ["general horticultural reference", "university extension guides"]}')
