  VALUES ('boysenberry','Boysenberry','Rubus ursinus x idaeus','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','half-hardy','spring',0,4,'Plant in early spring after frost danger passes; boysenberries are trailing types requiring a stout trellis.',5,9,48,72,24,48,72,120,'full','moderate','Boysenberries are vigorous trailing hybrids (blackberry x raspberry x loganberry lineage) that must be trained to a two- or three-wire trellis at 3 and 5 ft. Cut all fruited canes to the ground after the summer harvest and tie new canes along the wires for next year''s crop. Harvest when berries turn deep maroon-purple and have a rich, winey aroma. In zone 5–6 winters, remove canes from wires and lay them on the ground under mulch for protection.','["general horticultural reference", "university extension guides"]','{"slug": "boysenberry", "common_name": "Boysenberry", "scientific_name": "Rubus ursinus x idaeus", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in early spring after frost danger passes; boysenberries are trailing types requiring a stout trellis."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "moderate", "directions": "Boysenberries are vigorous trailing hybrids (blackberry x raspberry x loganberry lineage) that must be trained to a two- or three-wire trellis at 3 and 5 ft. Cut all fruited canes to the ground after the summer harvest and tie new canes along the wires for next year''s crop. Harvest when berries turn deep maroon-purple and have a rich, winey aroma. In zone 5–6 winters, remove canes from wires and lay them on the ground under mulch for protection.", "sources": ["general horticultural reference", "university extension guides"]}')
