  VALUES ('cranberry','Cranberry','Vaccinium macrocarpon','berry','ground fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','transplant','perennial','hardy','spring',0,4,'Plant rooted cuttings in spring in acidic, peaty, moisture-retentive soil with access to irrigation.',2,6,12,18,6,10,24,36,'full','high','Cranberries require strongly acidic soil (pH 4.0–5.0), consistent moisture, and sandy-peat substrate — conditions that closely mimic their native bog habitat. A 3–4 in layer of coarse sand mulch helps suppress weeds and maintains the proper surface environment. The vines are slow to establish and typically take 3–4 years to produce a meaningful crop. Harvest in fall when berries turn deep red and bounce when dropped; home growers pick by hand rather than flooding.','["general horticultural reference", "university extension guides"]','{"slug": "cranberry", "common_name": "Cranberry", "scientific_name": "Vaccinium macrocarpon", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings in spring in acidic, peaty, moisture-retentive soil with access to irrigation."}, "usda_zones": {"min": 2, "max": 6}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 10}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "high", "directions": "Cranberries require strongly acidic soil (pH 4.0–5.0), consistent moisture, and sandy-peat substrate — conditions that closely mimic their native bog habitat. A 3–4 in layer of coarse sand mulch helps suppress weeds and maintains the proper surface environment. The vines are slow to establish and typically take 3–4 years to produce a meaningful crop. Harvest in fall when berries turn deep red and bounce when dropped; home growers pick by hand rather than flooding.", "sources": ["general horticultural reference", "university extension guides"]}')
