INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('fuzzy-kiwi','Fuzzy Kiwi','Actinidia deliciosa','berry','vine fruit',NULL,NULL,NULL,NULL,1825,2555,'transplant','cutting','perennial','half-hardy','spring',0,4,'Plant after last frost in spring; requires a long frost-free season of 200–240 days for fruit to mature.',7,9,120,180,120,240,120,240,'full','moderate','Fuzzy kiwi (the standard grocery-store kiwifruit) requires a long, warm growing season and is best suited to zones 7–9 with at least 200 frost-free days. Like hardy kiwi, it is dioecious and requires male and female plants — one male pollinates up to 8 females. Train vines on a T-bar or pergola trellis and prune hard each dormant season to manage the vigorous growth. Harvest in late fall before hard frost when the seeds have turned black and the flesh is tender; fruit ripens off the vine.','["general horticultural reference", "university extension guides"]','{"slug": "fuzzy-kiwi", "common_name": "Fuzzy Kiwi", "scientific_name": "Actinidia deliciosa", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 2555}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant after last frost in spring; requires a long frost-free season of 200–240 days for fruit to mature."}, "usda_zones": {"min": 7, "max": 9}, "spacing_in": {"min": 120, "max": 180}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Fuzzy kiwi (the standard grocery-store kiwifruit) requires a long, warm growing season and is best suited to zones 7–9 with at least 200 frost-free days. Like hardy kiwi, it is dioecious and requires male and female plants — one male pollinates up to 8 females. Train vines on a T-bar or pergola trellis and prune hard each dormant season to manage the vigorous growth. Harvest in late fall before hard frost when the seeds have turned black and the flesh is tender; fruit ripens off the vine.", "sources": ["general horticultural reference", "university extension guides"]}')
