  VALUES ('hardy-kiwi','Hardy Kiwi','Actinidia arguta','berry','vine fruit',NULL,NULL,NULL,NULL,1460,2190,'transplant','cutting','perennial','hardy','spring',0,4,'Plant in spring after frost danger; provide a very sturdy trellis or pergola capable of holding hundreds of pounds of vine.',4,8,120,180,120,240,120,240,'full','moderate','Hardy kiwi vines are dioecious — plant one male vine for every 6–8 female vines or choose a self-fertile cultivar such as ''Issai''. The vines can take 4–7 years to bear fruit but become very productive once established, requiring a pergola or heavy-gauge trellis rated to hold at least 200 lbs. Prune to a permanent framework of main arms and renewal spurs each late winter, cutting lateral shoots back to 2–4 buds. Harvest when smooth, grape-sized fruits yield slightly to pressure and taste sweet.','["general horticultural reference", "university extension guides"]','{"slug": "hardy-kiwi", "common_name": "Hardy Kiwi", "scientific_name": "Actinidia arguta", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2190}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after frost danger; provide a very sturdy trellis or pergola capable of holding hundreds of pounds of vine."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 120, "max": 180}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Hardy kiwi vines are dioecious — plant one male vine for every 6–8 female vines or choose a self-fertile cultivar such as ''Issai''. The vines can take 4–7 years to bear fruit but become very productive once established, requiring a pergola or heavy-gauge trellis rated to hold at least 200 lbs. Prune to a permanent framework of main arms and renewal spurs each late winter, cutting lateral shoots back to 2–4 buds. Harvest when smooth, grape-sized fruits yield slightly to pressure and taste sweet.", "sources": ["general horticultural reference", "university extension guides"]}')
