INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('highbush-blueberry','Highbush Blueberry','Vaccinium corymbosum','berry','shrub fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','hardy','spring',0,4,'Plant dormant bare-root or container stock in early spring once soil is workable; fall planting is possible in zones 6–8.',4,7,48,72,60,96,48,72,'full','moderate','Blueberries require acidic soil with a pH of 4.5–5.5; amend with elemental sulfur and use acidic mulch such as pine bark or wood chips 3–4 in deep. Plant at least two cultivars for cross-pollination and better fruit set. Prune out old canes older than 6 years at the base each late winter to stimulate productive new wood. Harvest when berries turn deep blue and detach with minimal resistance, typically 7–10 days after color change.','["general horticultural reference", "university extension guides"]','{"slug": "highbush-blueberry", "common_name": "Highbush Blueberry", "scientific_name": "Vaccinium corymbosum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant dormant bare-root or container stock in early spring once soil is workable; fall planting is possible in zones 6–8."}, "usda_zones": {"min": 4, "max": 7}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 60, "max": 96}, "spread_in": {"min": 48, "max": 72}, "sun": "full", "water": "moderate", "directions": "Blueberries require acidic soil with a pH of 4.5–5.5; amend with elemental sulfur and use acidic mulch such as pine bark or wood chips 3–4 in deep. Plant at least two cultivars for cross-pollination and better fruit set. Prune out old canes older than 6 years at the base each late winter to stimulate productive new wood. Harvest when berries turn deep blue and detach with minimal resistance, typically 7–10 days after color change.", "sources": ["general horticultural reference", "university extension guides"]}')
