  VALUES ('honeyberry-haskap','Honeyberry / Haskap','Lonicera caerulea','berry','shrub fruit',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','hardy','spring',0,4,'Plant two or more compatible cultivars in early spring for cross-pollination; haskap blooms very early and needs a matching early-blooming partner.',2,7,48,72,36,72,36,60,'full','moderate','Honeyberries are among the earliest fruits to ripen — often 2–3 weeks before strawberries — and flowers can survive temperatures as low as -4°F, making them ideal for short-season climates. Two compatible cultivars from the same breeding group must be planted for cross-pollination. Minimal pruning is needed for the first 5 years; thereafter, remove a few of the oldest, thickest canes annually to renew. Harvest when berries are entirely blue-purple inside (cut one open to check), as color alone can be misleading.','["general horticultural reference", "university extension guides"]','{"slug": "honeyberry-haskap", "common_name": "Honeyberry / Haskap", "scientific_name": "Lonicera caerulea", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant two or more compatible cultivars in early spring for cross-pollination; haskap blooms very early and needs a matching early-blooming partner."}, "usda_zones": {"min": 2, "max": 7}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "moderate", "directions": "Honeyberries are among the earliest fruits to ripen — often 2–3 weeks before strawberries — and flowers can survive temperatures as low as -4°F, making them ideal for short-season climates. Two compatible cultivars from the same breeding group must be planted for cross-pollination. Minimal pruning is needed for the first 5 years; thereafter, remove a few of the oldest, thickest canes annually to renew. Harvest when berries are entirely blue-purple inside (cut one open to check), as color alone can be misleading.", "sources": ["general horticultural reference", "university extension guides"]}')
