  VALUES ('lingonberry','Lingonberry','Vaccinium vitis-idaea','berry','ground fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','transplant','perennial','hardy','spring',0,4,'Plant rooted plugs or divisions in early spring in acidic, well-drained soil; also useful as a groundcover under acid-loving shrubs.',2,7,12,18,8,16,12,24,'partial','moderate','Lingonberries require acidic soil (pH 4.5–5.5) and perform well as an ornamental groundcover in zones 2–7. They produce two crops per year — a smaller crop in midsummer and a larger one in fall. Minimal pruning is needed; shear plants to 3–4 in every few years to rejuvenate. Harvest when berries are deep red and slightly tart; they store well refrigerated and are traditionally used in Scandinavian preserves and sauces.','["general horticultural reference", "university extension guides"]','{"slug": "lingonberry", "common_name": "Lingonberry", "scientific_name": "Vaccinium vitis-idaea", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted plugs or divisions in early spring in acidic, well-drained soil; also useful as a groundcover under acid-loving shrubs."}, "usda_zones": {"min": 2, "max": 7}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 8, "max": 16}, "spread_in": {"min": 12, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Lingonberries require acidic soil (pH 4.5–5.5) and perform well as an ornamental groundcover in zones 2–7. They produce two crops per year — a smaller crop in midsummer and a larger one in fall. Minimal pruning is needed; shear plants to 3–4 in every few years to rejuvenate. Harvest when berries are deep red and slightly tart; they store well refrigerated and are traditionally used in Scandinavian preserves and sauces.", "sources": ["general horticultural reference", "university extension guides"]}')
