  VALUES ('lowbush-blueberry','Lowbush Blueberry','Vaccinium angustifolium','berry','shrub fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','transplant','perennial','hardy','spring',0,4,'Plant divisions or rooted cuttings in early spring in very acidic, well-drained soil.',3,6,18,24,12,24,18,36,'full','low','Lowbush blueberries require strongly acidic soil (pH 4.0–5.0) and spread by underground rhizomes to form colonies. Manage in a two-year cycle: mow or burn half the planting to the ground each year so alternating sections produce a full crop annually. Harvest in midsummer when berries are deep blue-purple and sweet. Drought-tolerant once established, but irrigation during fruit fill improves berry size.','["general horticultural reference", "university extension guides"]','{"slug": "lowbush-blueberry", "common_name": "Lowbush Blueberry", "scientific_name": "Vaccinium angustifolium", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or rooted cuttings in early spring in very acidic, well-drained soil."}, "usda_zones": {"min": 3, "max": 6}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "low", "directions": "Lowbush blueberries require strongly acidic soil (pH 4.0–5.0) and spread by underground rhizomes to form colonies. Manage in a two-year cycle: mow or burn half the planting to the ground each year so alternating sections produce a full crop annually. Harvest in midsummer when berries are deep blue-purple and sweet. Drought-tolerant once established, but irrigation during fruit fill improves berry size.", "sources": ["general horticultural reference", "university extension guides"]}')
