  VALUES ('red-currant','Red Currant','Ribes rubrum','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','cutting','perennial','hardy','spring',0,3,'Plant hardwood cuttings or bare-root stock in early spring as soon as soil is workable.',3,7,48,60,36,60,36,60,'partial','moderate','Red currants fruit heavily on spurs of wood two years old and older; prune each late winter to keep 8–12 canes of mixed ages and remove any cane older than 5 years. They tolerate more shade than most fruits and appreciate afternoon shelter in hot climates. Harvest entire strigs (clusters) when berries are uniformly bright red and slightly translucent. Check state restrictions on Ribes planting before ordering.','["general horticultural reference", "university extension guides"]','{"slug": "red-currant", "common_name": "Red Currant", "scientific_name": "Ribes rubrum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Plant hardwood cuttings or bare-root stock in early spring as soon as soil is workable."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 48, "max": 60}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 36, "max": 60}, "sun": "partial", "water": "moderate", "directions": "Red currants fruit heavily on spurs of wood two years old and older; prune each late winter to keep 8–12 canes of mixed ages and remove any cane older than 5 years. They tolerate more shade than most fruits and appreciate afternoon shelter in hot climates. Harvest entire strigs (clusters) when berries are uniformly bright red and slightly translucent. Check state restrictions on Ribes planting before ordering.", "sources": ["general horticultural reference", "university extension guides"]}')
