INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('strawberry-june-bearing','Strawberry (June-Bearing)','Fragaria x ananassa','berry','ground fruit',NULL,NULL,NULL,NULL,365,425,'transplant','transplant','perennial','hardy','last_frost',-2,2,'Set bare-root crowns in early spring as soon as soil can be worked, keeping the crown level with the soil surface.',3,10,12,18,6,12,12,24,'full','moderate','Plant bare-root crowns in spring with the crown at soil level, setting runners into a matted-row system 12–18 in apart. Pinch all blossoms the first year to build root vigor; harvest begins the following June when berries are uniformly red and pull easily from the stem. Renovate beds immediately after harvest by mowing foliage to 3–4 in and thinning plants to 4–6 per square foot. Mulch crowns with straw in fall in zones 4 and colder.','["general horticultural reference", "university extension guides"]','{"slug": "strawberry-june-bearing", "common_name": "Strawberry (June-Bearing)", "scientific_name": "Fragaria x ananassa", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 425}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Set bare-root crowns in early spring as soon as soil can be worked, keeping the crown level with the soil surface."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Plant bare-root crowns in spring with the crown at soil level, setting runners into a matted-row system 12–18 in apart. Pinch all blossoms the first year to build root vigor; harvest begins the following June when berries are uniformly red and pull easily from the stem. Renovate beds immediately after harvest by mowing foliage to 3–4 in and thinning plants to 4–6 per square foot. Mulch crowns with straw in fall in zones 4 and colder.", "sources": ["general horticultural reference", "university extension guides"]}')
