  VALUES ('summer-raspberry','Summer Raspberry','Rubus idaeus','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','hardy','spring',0,4,'Plant dormant bare-root canes in early spring as soon as soil can be worked.',3,9,18,24,48,72,18,36,'full','moderate','Summer raspberries fruit on floricanes — canes produced in year one that overwinter and bear fruit the following summer. After harvest, cut all fruited floricanes to the ground and thin new primocanes to 4–6 per linear foot for best airflow. Support canes on a two-wire trellis at 3 and 5 ft. Harvest when berries pull cleanly from the plug with no resistance, typically over 3–4 weeks in early summer.','["general horticultural reference", "university extension guides"]','{"slug": "summer-raspberry", "common_name": "Summer Raspberry", "scientific_name": "Rubus idaeus", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant dormant bare-root canes in early spring as soon as soil can be worked."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "moderate", "directions": "Summer raspberries fruit on floricanes — canes produced in year one that overwinter and bear fruit the following summer. After harvest, cut all fruited floricanes to the ground and thin new primocanes to 4–6 per linear foot for best airflow. Support canes on a two-wire trellis at 3 and 5 ft. Harvest when berries pull cleanly from the plug with no resistance, typically over 3–4 weeks in early summer.", "sources": ["general horticultural reference", "university extension guides"]}')
