INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('wine-grape','Wine Grape','Vitis vinifera','berry','vine fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','cutting','perennial','half-hardy','spring',0,4,'Plant grafted or own-rooted dormant vines in early spring on a well-drained slope with good air drainage.',6,10,72,96,60,96,72,96,'full','low','Wine grapes thrive in lean, well-drained soils with a pH of 5.5–6.5 and perform best on slopes with excellent air circulation to reduce disease pressure. Establish a vertical shoot positioning (VSP) trellis with catch wires at 4 and 5 ft above the cordon wire. Rigorous dormant pruning — leaving only 30–60 buds per vine depending on vigor — is essential for fruit quality. Harvest timing is cultivar- and use-specific; measure Brix (sugar) with a refractometer and monitor seed color and berry flavor.','["general horticultural reference", "university extension guides"]','{"slug": "wine-grape", "common_name": "Wine Grape", "scientific_name": "Vitis vinifera", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant grafted or own-rooted dormant vines in early spring on a well-drained slope with good air drainage."}, "usda_zones": {"min": 6, "max": 10}, "spacing_in": {"min": 72, "max": 96}, "height_in": {"min": 60, "max": 96}, "spread_in": {"min": 72, "max": 96}, "sun": "full", "water": "low", "directions": "Wine grapes thrive in lean, well-drained soils with a pH of 5.5–6.5 and perform best on slopes with excellent air circulation to reduce disease pressure. Establish a vertical shoot positioning (VSP) trellis with catch wires at 4 and 5 ft above the cordon wire. Rigorous dormant pruning — leaving only 30–60 buds per vine depending on vigor — is essential for fruit quality. Harvest timing is cultivar- and use-specific; measure Brix (sugar) with a refractometer and monitor seed color and berry flavor.", "sources": ["general horticultural reference", "university extension guides"]}')
