  VALUES ('buckwheat','Buckwheat','Fagopyrum esculentum','cover-crop','broadleaf',3,5,50,80,30,45,'seed','direct','warm','tender','last_frost',1,8,'Sow anytime in warm frost-free weather; a fast summer smother crop that flowers in ~5 weeks.',3,11,1,2,24,48,4,8,'full','moderate','Broadcast seed about 1/2 in deep into warm soil; it sprouts within days and shades out weeds quickly. Cut or turn it under at first bloom, before it sets seed, or it will reseed. It also draws pollinators and helps make soil phosphorus available.','["general horticultural reference"]','{"slug": "buckwheat", "common_name": "Buckwheat", "scientific_name": "Fagopyrum esculentum", "category": "cover-crop", "subcategory": "broadleaf", "days_to_germination": {"min": 3, "max": 5}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 30, "max": 45}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 8}, "note": "Sow anytime in warm frost-free weather; a fast summer smother crop that flowers in ~5 weeks."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Broadcast seed about 1/2 in deep into warm soil; it sprouts within days and shades out weeds quickly. Cut or turn it under at first bloom, before it sets seed, or it will reseed. It also draws pollinators and helps make soil phosphorus available.", "sources": ["general horticultural reference"]}')
