INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('crimson-clover','Crimson Clover','Trifolium incarnatum','cover-crop','legume',7,14,45,75,70,90,'seed','direct','cool','half-hardy','first_frost',-8,-4,'Sow 4–8 weeks before first fall frost, or in early spring; fixes nitrogen and blooms crimson.',6,9,1,2,12,24,4,8,'full','moderate','Broadcast seed onto a raked bed at about 1/4 in depth and keep moist until established. Let it grow through winter, then mow and turn it under a few weeks before planting to release its fixed nitrogen. Terminate at early bloom for the best nitrogen return.','["general horticultural reference"]','{"slug": "crimson-clover", "common_name": "Crimson Clover", "scientific_name": "Trifolium incarnatum", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 45, "max": 75}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before first fall frost, or in early spring; fixes nitrogen and blooms crimson."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Broadcast seed onto a raked bed at about 1/4 in depth and keep moist until established. Let it grow through winter, then mow and turn it under a few weeks before planting to release its fixed nitrogen. Terminate at early bloom for the best nitrogen return.", "sources": ["general horticultural reference"]}')
