  VALUES ('field-peas','Field Peas (Austrian Winter Pea)','Pisum sativum subsp. arvense','cover-crop','legume',7,14,40,70,60,90,'seed','direct','cool','half-hardy','first_frost',-8,-4,'Sow 4–8 weeks before frost in fall, or in earliest spring; nitrogen-fixing and edible tender shoots.',6,9,1,2,18,36,4,8,'full','moderate','Sow inoculated seed about 1 in deep, often mixed with oats or rye for support. The vines fix nitrogen and produce edible pea shoots you can harvest before turning the crop under. Terminate at flowering for the best nitrogen contribution.','["general horticultural reference"]','{"slug": "field-peas", "common_name": "Field Peas (Austrian Winter Pea)", "scientific_name": "Pisum sativum subsp. arvense", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before frost in fall, or in earliest spring; nitrogen-fixing and edible tender shoots."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Sow inoculated seed about 1 in deep, often mixed with oats or rye for support. The vines fix nitrogen and produce edible pea shoots you can harvest before turning the crop under. Terminate at flowering for the best nitrogen contribution.", "sources": ["general horticultural reference"]}')
