  VALUES ('hairy-vetch','Hairy Vetch','Vicia villosa','cover-crop','legume',10,15,60,70,70,100,'seed','direct','cool','hardy','first_frost',-8,-4,'Sow 4–8 weeks before first frost, often mixed with winter rye which gives it something to climb.',4,8,1,2,12,36,6,12,'full','moderate','Sow seed about 1/2 in deep, ideally inoculated with the correct rhizobia and paired with a grass like rye for support. It overwinters and fixes a large amount of nitrogen by spring bloom. Terminate at early flowering for maximum nitrogen and easy breakdown.','["general horticultural reference"]','{"slug": "hairy-vetch", "common_name": "Hairy Vetch", "scientific_name": "Vicia villosa", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 10, "max": 15}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 70, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before first frost, often mixed with winter rye which gives it something to climb."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 12, "max": 36}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seed about 1/2 in deep, ideally inoculated with the correct rhizobia and paired with a grass like rye for support. It overwinters and fixes a large amount of nitrogen by spring bloom. Terminate at early flowering for maximum nitrogen and easy breakdown.", "sources": ["general horticultural reference"]}')
