INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('annual-phlox','Annual Phlox','Phlox drummondii','flower','annual',10,14,60,70,60,80,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; transplant is also possible starting 6–8 weeks early indoors.',3,10,6,10,6,18,6,10,'full','moderate','Sow seed 1/8 in deep and cover lightly, as darkness can aid germination. Annual phlox prefers cool growing conditions and puts on its best show in spring and early summer. Deadhead spent clusters regularly to prevent seed set and keep flowers coming. In hot climates, plants may slow in midsummer heat; cut back and they will often rebloom as temperatures cool in fall.','["general horticultural reference"]','{"slug": "annual-phlox", "common_name": "Annual Phlox", "scientific_name": "Phlox drummondii", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; transplant is also possible starting 6–8 weeks early indoors."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/8 in deep and cover lightly, as darkness can aid germination. Annual phlox prefers cool growing conditions and puts on its best show in spring and early summer. Deadhead spent clusters regularly to prevent seed set and keep flowers coming. In hot climates, plants may slow in midsummer heat; cut back and they will often rebloom as temperatures cool in fall.", "sources": ["general horticultural reference"]}')
