  VALUES ('annual-verbena','Annual Verbena','Verbena × hybrida','flower','annual',14,21,65,75,70,90,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed.',3,11,10,14,6,18,12,18,'full','low','Sow seed 1/8 in deep in moist starting mix; refrigerate seeds for 5–7 days before sowing to improve germination rates. Transplant after the last frost date into well-drained soil, as verbena is very susceptible to root rot in wet conditions. Shear plants back by one-third in midsummer if they become leggy to stimulate a fresh flush of bloom. Verbena thrives in heat and is drought tolerant once established.','["general horticultural reference"]','{"slug": "annual-verbena", "common_name": "Annual Verbena", "scientific_name": "Verbena × hybrida", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 10, "max": 14}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seed 1/8 in deep in moist starting mix; refrigerate seeds for 5–7 days before sowing to improve germination rates. Transplant after the last frost date into well-drained soil, as verbena is very susceptible to root rot in wet conditions. Shear plants back by one-third in midsummer if they become leggy to stimulate a fresh flush of bloom. Verbena thrives in heat and is drought tolerant once established.", "sources": ["general horticultural reference"]}')
