INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('astilbe','Astilbe','Astilbe x arendsii','flower','perennial',21,28,65,70,90,120,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring or early fall in moist, organically rich soil with adequate moisture.',4,9,18,24,12,48,18,36,'partial','high','Plant crowns so the top of the rhizome sits 1–2 in below the soil surface in consistently moist, humus-rich soil — astilbe does not tolerate drought and will brown and decline quickly without adequate moisture. The feathery plumes in shades from white through pink to deep red are spectacular in shade and semi-shade gardens from late spring through summer. Leave the russet dried plumes standing through fall and winter for ornamental interest. Divide every 3–4 years in spring when flowering declines or the crown heaves above the soil surface.','["general horticultural reference"]','{"slug": "astilbe", "common_name": "Astilbe", "scientific_name": "Astilbe x arendsii", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring or early fall in moist, organically rich soil with adequate moisture."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 48}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "high", "directions": "Plant crowns so the top of the rhizome sits 1–2 in below the soil surface in consistently moist, humus-rich soil — astilbe does not tolerate drought and will brown and decline quickly without adequate moisture. The feathery plumes in shades from white through pink to deep red are spectacular in shade and semi-shade gardens from late spring through summer. Leave the russet dried plumes standing through fall and winter for ornamental interest. Divide every 3–4 years in spring when flowering declines or the crown heaves above the soil surface.", "sources": ["general horticultural reference"]}')
