  VALUES ('bearded-iris','Bearded Iris','Iris germanica','flower','perennial',NULL,NULL,NULL,NULL,270,365,'transplant','division','perennial','hardy','fall',-10,-6,'Plant rhizomes in late summer to early fall so roots establish before frost; divisions planted after midsummer bloom by the following spring.',3,9,12,18,24,36,18,24,'full','low','Set rhizomes horizontally with the top surface exposed to the sun — never bury them, as iris borers and rot thrive under covered rhizomes. Plant in late summer after bloom, with the fan of leaves pointing in the direction you want growth to spread. Divide every 3–4 years when clumps become overcrowded, discarding the woody center and replanting healthy outer fans. Good drainage is essential; soggy soil causes rhizome rot.','["general horticultural reference"]','{"slug": "bearded-iris", "common_name": "Bearded Iris", "scientific_name": "Iris germanica", "category": "flower", "subcategory": "perennial", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -10, "max": -6}, "note": "Plant rhizomes in late summer to early fall so roots establish before frost; divisions planted after midsummer bloom by the following spring."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Set rhizomes horizontally with the top surface exposed to the sun — never bury them, as iris borers and rot thrive under covered rhizomes. Plant in late summer after bloom, with the fan of leaves pointing in the direction you want growth to spread. Divide every 3–4 years when clumps become overcrowded, discarding the woody center and replanting healthy outer fans. Good drainage is essential; soggy soil causes rhizome rot.", "sources": ["general horticultural reference"]}')
