INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bee-balm','Bee Balm','Monarda didyma','flower','perennial',10,21,60,70,90,120,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring or fall in moist, well-drained soil with good air circulation.',4,9,18,24,24,48,24,36,'full','moderate','Plant in moist but well-drained soil rich in organic matter; good air circulation around plants is essential to minimize powdery mildew, their primary disease issue. The shaggy, two-lipped flowers are magnets for hummingbirds, bees, and butterflies from midsummer into fall. Deadhead spent blooms to extend flowering and cut plants back by one-third after the first flush to encourage a second wave. Divide every 2–3 years in spring because the spreading rhizomes exhaust the soil in the clump''s center.','["general horticultural reference"]','{"slug": "bee-balm", "common_name": "Bee Balm", "scientific_name": "Monarda didyma", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring or fall in moist, well-drained soil with good air circulation."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Plant in moist but well-drained soil rich in organic matter; good air circulation around plants is essential to minimize powdery mildew, their primary disease issue. The shaggy, two-lipped flowers are magnets for hummingbirds, bees, and butterflies from midsummer into fall. Deadhead spent blooms to extend flowering and cut plants back by one-third after the first flush to encourage a second wave. Divide every 2–3 years in spring because the spreading rhizomes exhaust the soil in the clump''s center.", "sources": ["general horticultural reference"]}')
