  VALUES ('breadseed-poppy','Breadseed Poppy','Papaver somniferum','flower','annual',10,20,50,65,60,90,'seed','direct','cool','hardy','last_frost',-8,-4,'Direct sow in very early spring or fall; seeds germinate in cool soil and seedlings tolerate frost.',3,9,6,12,24,48,8,12,'full','moderate','Surface sow by scattering seed on bare ground and pressing lightly without covering, as light aids germination. Breadseed poppies resent root disturbance and must be sown in place. Thin to 6–12 in when seedlings are 2 in tall. The ornamental seedpods are striking after petals drop and are valuable dried; harvest when the cap at the top turns from green to tan.','["general horticultural reference"]','{"slug": "breadseed-poppy", "common_name": "Breadseed Poppy", "scientific_name": "Papaver somniferum", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 20}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Direct sow in very early spring or fall; seeds germinate in cool soil and seedlings tolerate frost."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Surface sow by scattering seed on bare ground and pressing lightly without covering, as light aids germination. Breadseed poppies resent root disturbance and must be sown in place. Thin to 6–12 in when seedlings are 2 in tall. The ornamental seedpods are striking after petals drop and are valuable dried; harvest when the cap at the top turns from green to tan.", "sources": ["general horticultural reference"]}')
