  VALUES ('california-poppy','California Poppy','Eschscholzia californica','flower','annual',10,14,50,65,50,75,'seed','direct','cool','hardy','last_frost',-8,-4,'Direct sow in early spring or fall; seeds need cool soil to germinate and tolerate light frost.',3,11,4,6,10,18,6,10,'full','low','Scatter seed on the soil surface and rake lightly to cover 1/16–1/8 in deep. California poppies hate transplanting due to a delicate taproot, so sow where plants are to grow. They thrive in poor, dry soils and need little or no supplemental water once established. Deadhead to extend bloom, or let plants self-sow freely for a naturalized planting.','["general horticultural reference"]','{"slug": "california-poppy", "common_name": "California Poppy", "scientific_name": "Eschscholzia californica", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 50, "max": 75}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Direct sow in early spring or fall; seeds need cool soil to germinate and tolerate light frost."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 10, "max": 18}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "low", "directions": "Scatter seed on the soil surface and rake lightly to cover 1/16–1/8 in deep. California poppies hate transplanting due to a delicate taproot, so sow where plants are to grow. They thrive in poor, dry soils and need little or no supplemental water once established. Deadhead to extend bloom, or let plants self-sow freely for a naturalized planting.", "sources": ["general horticultural reference"]}')
