INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('celosia','Celosia','Celosia argentea','flower','annual',6,14,70,80,60,90,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant only after soil is warm, as cold temperatures cause stunted plants.',3,11,6,12,6,36,6,12,'full','moderate','Sow seed on the surface of moist starting mix and lightly press in — seed needs light and warmth to germinate. Do not rush transplanting into cold soil, as chilling causes plants to stall and go prematurely to seed. Deadhead spent plumes on crested and feathered types to extend the display. Celosia makes an excellent dried flower; harvest spikes just as they reach full color.','["general horticultural reference"]','{"slug": "celosia", "common_name": "Celosia", "scientific_name": "Celosia argentea", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 6, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant only after soil is warm, as cold temperatures cause stunted plants."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 6, "max": 36}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seed on the surface of moist starting mix and lightly press in — seed needs light and warmth to germinate. Do not rush transplanting into cold soil, as chilling causes plants to stall and go prematurely to seed. Deadhead spent plumes on crested and feathered types to extend the display. Celosia makes an excellent dried flower; harvest spikes just as they reach full color.", "sources": ["general horticultural reference"]}')
