INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('crocus','Crocus','Crocus spp.','flower','bulb',NULL,NULL,NULL,NULL,120,180,'transplant','bulb','perennial','hardy','fall',-10,-6,'Plant corms in fall, 6–10 weeks before the ground freezes, for late-winter to early-spring bloom.',3,8,3,4,4,6,3,4,'full','low','Plant corms pointed side up at a depth of 3–4 in in well-drained soil; they naturalize quickly and look best planted in large, informal drifts. Squirrels frequently dig freshly planted corms, so covering the bed with wire mesh until the ground freezes can protect plantings. Foliage is narrow and grassy; allow it to die back completely before removing. Species crocus tend to be more reliably perennial than large-flowered Dutch types.','["general horticultural reference"]','{"slug": "crocus", "common_name": "Crocus", "scientific_name": "Crocus spp.", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -10, "max": -6}, "note": "Plant corms in fall, 6–10 weeks before the ground freezes, for late-winter to early-spring bloom."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 3, "max": 4}, "height_in": {"min": 4, "max": 6}, "spread_in": {"min": 3, "max": 4}, "sun": "full", "water": "low", "directions": "Plant corms pointed side up at a depth of 3–4 in in well-drained soil; they naturalize quickly and look best planted in large, informal drifts. Squirrels frequently dig freshly planted corms, so covering the bed with wire mesh until the ground freezes can protect plantings. Foliage is narrow and grassy; allow it to die back completely before removing. Species crocus tend to be more reliably perennial than large-flowered Dutch types.", "sources": ["general horticultural reference"]}')
