INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('dahlia','Dahlia','Dahlia pinnata','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','tuber','perennial','tender','last_frost',0,2,'Plant tubers after the last frost date when soil has warmed to at least 60°F.',8,11,18,36,18,72,18,36,'full','moderate','Plant tubers horizontally 4–6 in deep with the eye pointing up after the last frost when soil reaches 60°F; set a stake at planting time to avoid spearing the tuber later. Pinch the growing tip when plants are 12 in tall to encourage branching and more flowers. In zones below 8, dig tubers after the first killing frost, cure them for a week, then store in slightly damp peat at 40–50°F through winter. Disbudding side buds around the main bud produces exhibition-quality blooms.','["general horticultural reference"]','{"slug": "dahlia", "common_name": "Dahlia", "scientific_name": "Dahlia pinnata", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "tuber", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant tubers after the last frost date when soil has warmed to at least 60°F."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 18, "max": 36}, "height_in": {"min": 18, "max": 72}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "moderate", "directions": "Plant tubers horizontally 4–6 in deep with the eye pointing up after the last frost when soil reaches 60°F; set a stake at planting time to avoid spearing the tuber later. Pinch the growing tip when plants are 12 in tall to encourage branching and more flowers. In zones below 8, dig tubers after the first killing frost, cure them for a week, then store in slightly damp peat at 40–50°F through winter. Disbudding side buds around the main bud produces exhibition-quality blooms.", "sources": ["general horticultural reference"]}')
