  VALUES ('daylily','Daylily','Hemerocallis hybrida','flower','perennial',NULL,NULL,NULL,NULL,60,90,'transplant','division','perennial','hardy','spring',0,4,'Plant bare-root divisions in spring or fall; set crowns just 1 in below soil level.',3,9,18,24,18,48,18,36,'full','moderate','Plant fans with the crown about 1 in deep, spreading roots outward over a small mound of soil in the hole. Water thoroughly after planting and keep consistently moist the first season. Divide overcrowded clumps every 4–5 years in early spring or late summer when bloom quality declines. Removing spent scapes after all buds have opened keeps the planting tidy.','["general horticultural reference"]','{"slug": "daylily", "common_name": "Daylily", "scientific_name": "Hemerocallis hybrida", "category": "flower", "subcategory": "perennial", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root divisions in spring or fall; set crowns just 1 in below soil level."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 48}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "moderate", "directions": "Plant fans with the crown about 1 in deep, spreading roots outward over a small mound of soil in the hole. Water thoroughly after planting and keep consistently moist the first season. Divide overcrowded clumps every 4–5 years in early spring or late summer when bloom quality declines. Removing spent scapes after all buds have opened keeps the planting tidy.", "sources": ["general horticultural reference"]}')
