INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('delphinium','Delphinium','Delphinium elatum','flower','perennial',14,21,60,70,365,730,'seed','indoor-start','perennial','half-hardy','last_frost',-12,-10,'Start seeds indoors 10–12 weeks before last frost; fresh seed germinates best and benefits from 1–2 weeks of cold stratification.',3,7,18,24,36,72,24,36,'full','moderate','Use fresh seed — viability drops quickly in storage — and cold-stratify for 1–2 weeks before sowing at 60–70°F for best germination. Transplant after the last frost into rich, well-drained, slightly alkaline soil and stake early, as the tall spikes are highly susceptible to wind damage. Cut flower spikes back to basal foliage after the first bloom to encourage a second, smaller flush in late summer. All parts of the plant are toxic; all plant contact should be followed by hand washing.','["general horticultural reference"]','{"slug": "delphinium", "common_name": "Delphinium", "scientific_name": "Delphinium elatum", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start seeds indoors 10–12 weeks before last frost; fresh seed germinates best and benefits from 1–2 weeks of cold stratification."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Use fresh seed — viability drops quickly in storage — and cold-stratify for 1–2 weeks before sowing at 60–70°F for best germination. Transplant after the last frost into rich, well-drained, slightly alkaline soil and stake early, as the tall spikes are highly susceptible to wind damage. Cut flower spikes back to basal foliage after the first bloom to encourage a second, smaller flush in late summer. All parts of the plant are toxic; all plant contact should be followed by hand washing.", "sources": ["general horticultural reference"]}')
