INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('false-indigo','False Indigo','Baptisia australis','flower','perennial',21,30,65,75,365,1095,'seed','direct','perennial','hardy','fall',-6,-4,'Direct sow in fall for natural cold stratification, or scarify and cold-stratify seeds before spring planting.',3,9,36,48,36,60,36,48,'full','low','Scarify seeds and cold-stratify for 4–6 weeks before spring sowing, or direct sow in fall to let natural winter conditions break dormancy. Baptisia is a slow-starting plant — expect minimal bloom for the first 2–3 years, but once established, the clump requires virtually no care and lives for decades. The indigo-blue lupine-like flower spikes appear in late spring and are followed by attractive, inflated seedpods that rattle in the wind. Do not attempt to transplant established plants, as the deep taproot does not tolerate disturbance.','["general horticultural reference"]','{"slug": "false-indigo", "common_name": "False Indigo", "scientific_name": "Baptisia australis", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 30}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 365, "max": 1095}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow in fall for natural cold stratification, or scarify and cold-stratify seeds before spring planting."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 36, "max": 48}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 36, "max": 48}, "sun": "full", "water": "low", "directions": "Scarify seeds and cold-stratify for 4–6 weeks before spring sowing, or direct sow in fall to let natural winter conditions break dormancy. Baptisia is a slow-starting plant — expect minimal bloom for the first 2–3 years, but once established, the clump requires virtually no care and lives for decades. The indigo-blue lupine-like flower spikes appear in late spring and are followed by attractive, inflated seedpods that rattle in the wind. Do not attempt to transplant established plants, as the deep taproot does not tolerate disturbance.", "sources": ["general horticultural reference"]}')
