  VALUES ('four-o-clock','Four O''Clock','Mirabilis jalapa','flower','annual',7,14,65,75,60,90,'seed','direct','warm','tender','last_frost',0,2,'Direct sow after last frost when soil is warm; can also start indoors 4–6 weeks early.',3,11,12,18,18,36,18,24,'full','low','Sow seed 1/4–1/2 in deep in a warm, sunny location after the last frost. Four o''clocks form a tuberous root and tolerate drought well once established. Flowers open in late afternoon and remain open through the following morning, releasing a sweet fragrance that attracts sphinx moths. Plants self-sow prolifically and the fleshy roots can be dug and stored in frost-prone areas.','["general horticultural reference"]','{"slug": "four-o-clock", "common_name": "Four O''Clock", "scientific_name": "Mirabilis jalapa", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow after last frost when soil is warm; can also start indoors 4–6 weeks early."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seed 1/4–1/2 in deep in a warm, sunny location after the last frost. Four o''clocks form a tuberous root and tolerate drought well once established. Flowers open in late afternoon and remain open through the following morning, releasing a sweet fragrance that attracts sphinx moths. Plants self-sow prolifically and the fleshy roots can be dug and stored in frost-prone areas.", "sources": ["general horticultural reference"]}')
