  VALUES ('foxglove','Foxglove','Digitalis purpurea','flower','perennial',14,21,60,70,365,730,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; seeds need light and should not be covered.',4,9,18,24,36,72,18,24,'partial','moderate','Press seeds onto the surface of moist potting mix under bright light — do not cover, as light aids germination. Foxgloves are biennial or short-lived perennials; most produce a rosette in year 1 and the spectacular tall spikes in year 2 before setting seed and dying. Cutting the main spike after bloom often stimulates smaller side spikes for additional flowers, and self-sowing keeps the planting going indefinitely. All parts of the plant are highly toxic; use caution and wash hands thoroughly after handling.','["general horticultural reference"]','{"slug": "foxglove", "common_name": "Foxglove", "scientific_name": "Digitalis purpurea", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; seeds need light and should not be covered."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 18, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Press seeds onto the surface of moist potting mix under bright light — do not cover, as light aids germination. Foxgloves are biennial or short-lived perennials; most produce a rosette in year 1 and the spectacular tall spikes in year 2 before setting seed and dying. Cutting the main spike after bloom often stimulates smaller side spikes for additional flowers, and self-sowing keeps the planting going indefinitely. All parts of the plant are highly toxic; use caution and wash hands thoroughly after handling.", "sources": ["general horticultural reference"]}')
