INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('gladiolus','Gladiolus','Gladiolus spp.','flower','bulb',NULL,NULL,NULL,NULL,60,90,'transplant','bulb','perennial','tender','last_frost',0,6,'Plant corms after the last frost; make successive plantings every 2 weeks through early summer for extended bloom.',7,11,6,8,36,60,6,8,'full','moderate','Plant corms 4–6 in deep in well-drained soil with the pointed end up after the last frost; succession plant every 2 weeks through midsummer for continuous cut flowers. Tall varieties need staking; a single bamboo cane tied loosely to the stem works well. In zones below 7, dig corms after frost blackens the foliage, dry for 2–3 weeks, remove offsets (cormels), and store at 35–45°F in mesh bags through winter. Harvest cut spikes when the lowest 2–3 buds show color for longest vase life.','["general horticultural reference"]','{"slug": "gladiolus", "common_name": "Gladiolus", "scientific_name": "Gladiolus spp.", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant corms after the last frost; make successive plantings every 2 weeks through early summer for extended bloom."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 6, "max": 8}, "sun": "full", "water": "moderate", "directions": "Plant corms 4–6 in deep in well-drained soil with the pointed end up after the last frost; succession plant every 2 weeks through midsummer for continuous cut flowers. Tall varieties need staking; a single bamboo cane tied loosely to the stem works well. In zones below 7, dig corms after frost blackens the foliage, dry for 2–3 weeks, remove offsets (cormels), and store at 35–45°F in mesh bags through winter. Harvest cut spikes when the lowest 2–3 buds show color for longest vase life.", "sources": ["general horticultural reference"]}')
