  VALUES ('gomphrena','Gomphrena (Globe Amaranth)','Gomphrena globosa','flower','annual',7,14,70,80,60,80,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after all frost danger has passed.',3,11,8,12,12,24,8,12,'full','low','Sow seed 1/4 in deep in warm starting mix; soak seed overnight to speed germination. Gomphrena thrives in heat and humidity and is highly drought tolerant once established. The clover-like flowers hold their color and shape exceptionally well when dried — harvest stems just as the heads reach full color. Deadheading encourages continuous fresh bloom throughout the summer.','["general horticultural reference"]','{"slug": "gomphrena", "common_name": "Gomphrena (Globe Amaranth)", "scientific_name": "Gomphrena globosa", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "low", "directions": "Sow seed 1/4 in deep in warm starting mix; soak seed overnight to speed germination. Gomphrena thrives in heat and humidity and is highly drought tolerant once established. The clover-like flowers hold their color and shape exceptionally well when dried — harvest stems just as the heads reach full color. Deadheading encourages continuous fresh bloom throughout the summer.", "sources": ["general horticultural reference"]}')
