  VALUES ('hardy-geranium','Hardy Geranium','Geranium spp.','flower','perennial',14,21,60,70,60,90,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring or fall; tolerates a wide range of soil conditions once established.',4,9,18,24,12,24,18,36,'partial','moderate','Plant in well-drained soil in a location with morning sun and afternoon shade; hardy geraniums are adaptable to poor soils and are generally low-maintenance once established. Shear plants back by one-half after the initial bloom to refresh the foliage and encourage a second flush of flowers. The attractive lobed leaves often turn red or orange in fall, extending the ornamental season. Divide every 3–5 years in spring to reinvigorate the planting.','["general horticultural reference"]','{"slug": "hardy-geranium", "common_name": "Hardy Geranium", "scientific_name": "Geranium spp.", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring or fall; tolerates a wide range of soil conditions once established."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Plant in well-drained soil in a location with morning sun and afternoon shade; hardy geraniums are adaptable to poor soils and are generally low-maintenance once established. Shear plants back by one-half after the initial bloom to refresh the foliage and encourage a second flush of flowers. The attractive lobed leaves often turn red or orange in fall, extending the ornamental season. Divide every 3–5 years in spring to reinvigorate the planting.", "sources": ["general horticultural reference"]}')
