  VALUES ('hellebore','Hellebore','Helleborus x hybridus','flower','perennial',30,60,60,65,365,730,'transplant','division','perennial','hardy','spring',0,4,'Plant in spring or early fall in humus-rich, well-drained shade; transplanted divisions establish more reliably than seed.',4,9,18,24,12,24,18,24,'shade','moderate','Plant with the crown at soil level in well-drained, humus-rich soil in dappled to full shade — morning sun is tolerated, but afternoon sun causes leaf scorch. Hellebores bloom in late winter to early spring, often through snow, and the nodding flowers face downward; tipping the pot or planting on a slope allows a better view of the flower interior. Remove old foliage in late winter before new growth emerges to improve air circulation and reduce leaf spot diseases. Hellebores self-sow freely, and seedlings from hybrid plants will vary; divide named selections in early spring to maintain specific colors.','["general horticultural reference"]','{"slug": "hellebore", "common_name": "Hellebore", "scientific_name": "Helleborus x hybridus", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 30, "max": 60}, "germination_soil_temp_f": {"min": 60, "max": 65}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring or early fall in humus-rich, well-drained shade; transplanted divisions establish more reliably than seed."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 24}, "sun": "shade", "water": "moderate", "directions": "Plant with the crown at soil level in well-drained, humus-rich soil in dappled to full shade — morning sun is tolerated, but afternoon sun causes leaf scorch. Hellebores bloom in late winter to early spring, often through snow, and the nodding flowers face downward; tipping the pot or planting on a slope allows a better view of the flower interior. Remove old foliage in late winter before new growth emerges to improve air circulation and reduce leaf spot diseases. Hellebores self-sow freely, and seedlings from hybrid plants will vary; divide named selections in early spring to maintain specific colors.", "sources": ["general horticultural reference"]}')
