INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('hollyhock','Hollyhock','Alcea rosea','flower','perennial',10,14,60,70,365,730,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow in spring around the last frost date or in late summer for bloom the following year.',3,9,18,24,48,96,18,24,'full','moderate','Sow seeds 1/4 in deep; hollyhocks are biennial or short-lived perennials that flower the second year from seed and self-sow freely to maintain the planting. Rust fungus is the most common disease — look for orange pustules on leaf undersides and remove affected foliage promptly, avoiding overhead watering. Plant against walls or fences and provide loose staking for the tall, top-heavy flowering spikes. Allow some seed to mature and fall to keep the colony self-renewing.','["general horticultural reference"]','{"slug": "hollyhock", "common_name": "Hollyhock", "scientific_name": "Alcea rosea", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow in spring around the last frost date or in late summer for bloom the following year."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep; hollyhocks are biennial or short-lived perennials that flower the second year from seed and self-sow freely to maintain the planting. Rust fungus is the most common disease — look for orange pustules on leaf undersides and remove affected foliage promptly, avoiding overhead watering. Plant against walls or fences and provide loose staking for the tall, top-heavy flowering spikes. Allow some seed to mature and fall to keep the colony self-renewing.", "sources": ["general horticultural reference"]}')
