INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('impatiens','Impatiens','Impatiens walleriana','flower','annual',14,21,70,75,60,80,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost risk has passed and nights are warm.',3,11,8,12,6,24,8,18,'shade','moderate','Sow tiny seed on the surface of moist starting mix without covering — light is required for germination. Impatiens are one of the most reliable shade-tolerant annuals and will self-clean most spent flowers. Pinch plants back once after transplanting to encourage compact, bushy growth. Water consistently; wilting in heat is common and plants recover overnight, but chronic drought reduces flowering.','["general horticultural reference"]','{"slug": "impatiens", "common_name": "Impatiens", "scientific_name": "Impatiens walleriana", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost risk has passed and nights are warm."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 6, "max": 24}, "spread_in": {"min": 8, "max": 18}, "sun": "shade", "water": "moderate", "directions": "Sow tiny seed on the surface of moist starting mix without covering — light is required for germination. Impatiens are one of the most reliable shade-tolerant annuals and will self-clean most spent flowers. Pinch plants back once after transplanting to encourage compact, bushy growth. Water consistently; wilting in heat is common and plants recover overnight, but chronic drought reduces flowering.", "sources": ["general horticultural reference"]}')
