INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lupine','Lupine','Lupinus polyphyllus','flower','perennial',14,21,55,65,365,730,'seed','direct','perennial','hardy','last_frost',-4,0,'Direct sow outdoors in early spring or fall; nick or soak seeds overnight to improve germination.',4,8,18,24,24,48,18,24,'full','moderate','Scarify seeds with sandpaper or soak overnight in water to soften the hard seed coat before sowing 1/4 in deep in cool, slightly acidic, well-drained soil. Lupines fix atmospheric nitrogen via root nodules and thrive in lean soils without heavy fertilization — too much nitrogen promotes foliage over flowers. They prefer cool summers; in hot climates, they often perform as cool-season annuals, blooming in late spring and fading by midsummer. Deadhead promptly after the first flowering spike fades to encourage a second flush and prevent excessive self-seeding.','["general horticultural reference"]','{"slug": "lupine", "common_name": "Lupine", "scientific_name": "Lupinus polyphyllus", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow outdoors in early spring or fall; nick or soak seeds overnight to improve germination."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Scarify seeds with sandpaper or soak overnight in water to soften the hard seed coat before sowing 1/4 in deep in cool, slightly acidic, well-drained soil. Lupines fix atmospheric nitrogen via root nodules and thrive in lean soils without heavy fertilization — too much nitrogen promotes foliage over flowers. They prefer cool summers; in hot climates, they often perform as cool-season annuals, blooming in late spring and fading by midsummer. Deadhead promptly after the first flowering spike fades to encourage a second flush and prevent excessive self-seeding.", "sources": ["general horticultural reference"]}')
