INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('morning-glory','Morning Glory','Ipomoea purpurea','flower','annual',5,10,65,75,65,90,'seed','direct','warm','tender','last_frost',0,1,'Direct sow after last frost when soil is warm; or nick and soak seed overnight then start indoors 2–4 weeks early.',3,11,6,12,72,120,12,24,'full','moderate','Nick the hard seed coat with a file or soak in warm water for 8–12 hours before sowing 1/2 in deep to speed germination. Morning glories need a fence, trellis, or other support and are best sown directly at the base of their support. Avoid over-fertilizing, which promotes leaves at the expense of flowers. Blooms open in the morning and close by afternoon on each individual day.','["general horticultural reference"]','{"slug": "morning-glory", "common_name": "Morning Glory", "scientific_name": "Ipomoea purpurea", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 65, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 1}, "note": "Direct sow after last frost when soil is warm; or nick and soak seed overnight then start indoors 2–4 weeks early."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 72, "max": 120}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Nick the hard seed coat with a file or soak in warm water for 8–12 hours before sowing 1/2 in deep to speed germination. Morning glories need a fence, trellis, or other support and are best sown directly at the base of their support. Avoid over-fertilizing, which promotes leaves at the expense of flowers. Blooms open in the morning and close by afternoon on each individual day.", "sources": ["general horticultural reference"]}')
