  VALUES ('nasturtium','Nasturtium','Tropaeolum majus','flower','annual',7,14,55,65,35,60,'seed','direct','cool','half-hardy','last_frost',-2,0,'Direct sow 1–2 weeks before last frost; nasturtiums prefer cool soil and bolt in summer heat.',2,11,8,12,12,24,12,24,'full','low','Soak large seeds overnight then direct sow 1/2 in deep in poor, well-drained soil. Avoid fertilizing, as rich soil produces lush leaves at the expense of flowers. Deadhead spent blooms to prolong the season, or allow them to set seed and collect for next year. Both flowers and leaves are edible with a peppery flavor.','["general horticultural reference"]','{"slug": "nasturtium", "common_name": "Nasturtium", "scientific_name": "Tropaeolum majus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 35, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Direct sow 1–2 weeks before last frost; nasturtiums prefer cool soil and bolt in summer heat."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "low", "directions": "Soak large seeds overnight then direct sow 1/2 in deep in poor, well-drained soil. Avoid fertilizing, as rich soil produces lush leaves at the expense of flowers. Deadhead spent blooms to prolong the season, or allow them to set seed and collect for next year. Both flowers and leaves are edible with a peppery flavor.", "sources": ["general horticultural reference"]}')
