  VALUES ('new-england-aster','New England Aster','Symphyotrichum novae-angliae','flower','perennial',14,21,60,70,240,300,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; cold stratification for 4–6 weeks improves germination.',4,8,24,36,36,72,24,36,'full','moderate','Cold-stratify seeds for 4–6 weeks in a damp paper towel in the refrigerator before sowing indoors to improve germination rates. Pinch plants back by one-third in late spring to encourage bushier growth and delay bloom until fall, when their purple flowers are invaluable for pollinators. Tall varieties may need staking or can be grown through a peony cage. Divide clumps every 2–3 years in early spring to maintain vigor and prevent the center from dying out.','["general horticultural reference"]','{"slug": "new-england-aster", "common_name": "New England Aster", "scientific_name": "Symphyotrichum novae-angliae", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 240, "max": 300}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; cold stratification for 4–6 weeks improves germination."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Cold-stratify seeds for 4–6 weeks in a damp paper towel in the refrigerator before sowing indoors to improve germination rates. Pinch plants back by one-third in late spring to encourage bushier growth and delay bloom until fall, when their purple flowers are invaluable for pollinators. Tall varieties may need staking or can be grown through a peony cage. Divide clumps every 2–3 years in early spring to maintain vigor and prevent the center from dying out.", "sources": ["general horticultural reference"]}')
