INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('penstemon','Penstemon','Penstemon digitalis','flower','perennial',14,28,60,70,90,365,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; seeds benefit from 4 weeks of cold stratification.',3,8,18,24,24,48,18,24,'full','low','Cold-stratify seeds for 4 weeks in damp medium in the refrigerator before sowing indoors for best germination; transplant after the last frost into well-drained to dry soil. Penstemon thrives in poor, gravelly soil and is one of the most important native nectar plants for hummingbirds and native bees. The tubular white to pale pink flowers appear in late spring to early summer; deadhead to a basal rosette of leaves after bloom. Excellent drainage is critical — wet winter conditions are the leading cause of plant loss.','["general horticultural reference"]','{"slug": "penstemon", "common_name": "Penstemon", "scientific_name": "Penstemon digitalis", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 365}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; seeds benefit from 4 weeks of cold stratification."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Cold-stratify seeds for 4 weeks in damp medium in the refrigerator before sowing indoors for best germination; transplant after the last frost into well-drained to dry soil. Penstemon thrives in poor, gravelly soil and is one of the most important native nectar plants for hummingbirds and native bees. The tubular white to pale pink flowers appear in late spring to early summer; deadhead to a basal rosette of leaves after bloom. Excellent drainage is critical — wet winter conditions are the leading cause of plant loss.", "sources": ["general horticultural reference"]}')
