  VALUES ('petunia','Petunia','Petunia × hybrida','flower','annual',10,14,70,75,60,90,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after frost danger has passed.',3,11,12,18,6,18,12,36,'full','moderate','Sow tiny seed on the surface of moist starting mix — do not cover, as petunias need light to germinate. Pinch transplants by one-third when planting to encourage branching. Deadhead or shear back leggy plants by half in midsummer to renew vigor and flush of bloom. Feed every two weeks with a balanced liquid fertilizer for best performance.','["general horticultural reference"]','{"slug": "petunia", "common_name": "Petunia", "scientific_name": "Petunia × hybrida", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after frost danger has passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 12, "max": 36}, "sun": "full", "water": "moderate", "directions": "Sow tiny seed on the surface of moist starting mix — do not cover, as petunias need light to germinate. Pinch transplants by one-third when planting to encourage branching. Deadhead or shear back leggy plants by half in midsummer to renew vigor and flush of bloom. Feed every two weeks with a balanced liquid fertilizer for best performance.", "sources": ["general horticultural reference"]}')
