  VALUES ('portulaca','Portulaca (Moss Rose)','Portulaca grandiflora','flower','annual',7,14,70,80,50,70,'seed','direct','warm','tender','last_frost',0,2,'Direct sow on the soil surface after last frost when soil is warm; seed needs warmth and light to germinate.',2,11,6,12,4,8,12,18,'full','low','Scatter seed on the surface of sandy or gritty soil and press lightly — do not cover seed, as light is needed for germination. Portulaca is one of the most drought- and heat-tolerant annuals available, thriving in poor, dry soil where other flowers fail. Blooms open in full sun and close at night or in cloudy weather; modern varieties stay open longer. Self-sows readily in warm climates.','["general horticultural reference"]','{"slug": "portulaca", "common_name": "Portulaca (Moss Rose)", "scientific_name": "Portulaca grandiflora", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow on the soil surface after last frost when soil is warm; seed needs warmth and light to germinate."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 4, "max": 8}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Scatter seed on the surface of sandy or gritty soil and press lightly — do not cover seed, as light is needed for germination. Portulaca is one of the most drought- and heat-tolerant annuals available, thriving in poor, dry soil where other flowers fail. Blooms open in full sun and close at night or in cloudy weather; modern varieties stay open longer. Self-sows readily in warm climates.", "sources": ["general horticultural reference"]}')
