INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('russian-sage','Russian Sage','Perovskia atriplicifolia','flower','perennial',14,30,60,70,90,120,'transplant','division','perennial','hardy','spring',0,4,'Plant in spring after last frost in lean, well-drained soil; established plants are extremely drought-tolerant.',4,9,24,36,36,60,24,36,'full','low','Plant in poor to average, sharply drained soil in full sun — Russian sage declines quickly in fertile or moist soil and is highly susceptible to root rot in clay. Cut plants back hard in early spring (to about 6 in) just as new basal growth emerges; do not cut back in fall as the woody framework helps protect the crown. The airy silver stems and lavender-blue flowers create a haze of color from midsummer through fall and are beloved by pollinators. Deer avoid this plant due to its strongly aromatic foliage.','["general horticultural reference"]','{"slug": "russian-sage", "common_name": "Russian Sage", "scientific_name": "Perovskia atriplicifolia", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after last frost in lean, well-drained soil; established plants are extremely drought-tolerant."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Plant in poor to average, sharply drained soil in full sun — Russian sage declines quickly in fertile or moist soil and is highly susceptible to root rot in clay. Cut plants back hard in early spring (to about 6 in) just as new basal growth emerges; do not cut back in fall as the woody framework helps protect the crown. The airy silver stems and lavender-blue flowers create a haze of color from midsummer through fall and are beloved by pollinators. Deer avoid this plant due to its strongly aromatic foliage.", "sources": ["general horticultural reference"]}')
