INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sedum-stonecrop','Sedum / Stonecrop','Sedum spectabile / Hylotelephium spectabile','flower','perennial',14,28,60,70,120,180,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring or fall; division is easily done by digging and separating rooted stems.',3,9,18,24,18,24,18,24,'full','low','Plant in any well-drained soil — even poor, gravelly soil suits sedum perfectly; overly rich or moist soil causes floppy, open-centered plants. Tall sedums may flop in midseason; pinch once in late spring or grow through a support ring to keep them upright. Leave the russet seedheads standing through winter as they are attractive and provide structure in the dormant garden. Divide every 3–4 years in spring by separating the fleshy crown sections.','["general horticultural reference"]','{"slug": "sedum-stonecrop", "common_name": "Sedum / Stonecrop", "scientific_name": "Sedum spectabile / Hylotelephium spectabile", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring or fall; division is easily done by digging and separating rooted stems."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Plant in any well-drained soil — even poor, gravelly soil suits sedum perfectly; overly rich or moist soil causes floppy, open-centered plants. Tall sedums may flop in midseason; pinch once in late spring or grow through a support ring to keep them upright. Leave the russet seedheads standing through winter as they are attractive and provide structure in the dormant garden. Divide every 3–4 years in spring by separating the fleshy crown sections.", "sources": ["general horticultural reference"]}')
