INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sunflower','Sunflower','Helianthus annuus','flower','annual',7,10,65,85,60,90,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or just after last frost when soil is warm; succession sow every 2–3 weeks for extended bloom.',2,11,6,24,24,120,12,36,'full','low','Direct sow seed 1 in deep after the last frost date, thinning to final spacing once seedlings reach 6 in tall. Sunflowers prefer poor-to-average soil and resent transplanting due to a taproot. Single-stemmed types bloom once; branching varieties produce multiple heads if cut regularly. Harvest seed heads when the back of the head turns yellow-brown and seeds feel firm.','["general horticultural reference"]','{"slug": "sunflower", "common_name": "Sunflower", "scientific_name": "Helianthus annuus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or just after last frost when soil is warm; succession sow every 2–3 weeks for extended bloom."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 24}, "height_in": {"min": 24, "max": 120}, "spread_in": {"min": 12, "max": 36}, "sun": "full", "water": "low", "directions": "Direct sow seed 1 in deep after the last frost date, thinning to final spacing once seedlings reach 6 in tall. Sunflowers prefer poor-to-average soil and resent transplanting due to a taproot. Single-stemmed types bloom once; branching varieties produce multiple heads if cut regularly. Harvest seed heads when the back of the head turns yellow-brown and seeds feel firm.", "sources": ["general horticultural reference"]}')
