INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sweet-pea','Sweet Pea','Lathyrus odoratus','flower','annual',10,21,55,65,60,90,'seed','direct','cool','half-hardy','last_frost',-8,-4,'Direct sow outdoors 4–8 weeks before last frost; seeds prefer cool soil (55–65°F) and young plants tolerate frost.',3,9,4,6,24,72,6,12,'full','moderate','Nick or soak seeds overnight before sowing 1 in deep in cool, enriched soil at the base of a trellis. Sweet peas perform best during cool weather and decline as summer heat arrives — sow as early as possible. Cut flowers frequently, as even a few fading blooms left on the plant will trigger seed set and halt blooming. Provide sturdy support from the start, as vines climb to 4–6 ft.','["general horticultural reference"]','{"slug": "sweet-pea", "common_name": "Sweet Pea", "scientific_name": "Lathyrus odoratus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Direct sow outdoors 4–8 weeks before last frost; seeds prefer cool soil (55–65°F) and young plants tolerate frost."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 24, "max": 72}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Nick or soak seeds overnight before sowing 1 in deep in cool, enriched soil at the base of a trellis. Sweet peas perform best during cool weather and decline as summer heat arrives — sow as early as possible. Cut flowers frequently, as even a few fading blooms left on the plant will trigger seed set and halt blooming. Provide sturdy support from the start, as vines climb to 4–6 ft.", "sources": ["general horticultural reference"]}')
