INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('veronica-speedwell','Veronica / Speedwell','Veronica spicata','flower','perennial',14,28,65,70,90,120,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring or fall in well-drained soil; excellent drought tolerance once established.',3,8,18,24,12,24,18,24,'full','low','Plant in well-drained soil in full sun; speedwell is notably drought-tolerant and performs poorly in soggy or heavy clay conditions. The upright spikes of blue, pink, or white flowers bloom from late spring into summer and are excellent for cutting. Deadhead by removing spent spikes back to a lateral bud or leaf to extend the flowering period and prevent excessive self-seeding. Divide every 3–4 years in early spring to maintain vigor and an attractive mounding habit.','["general horticultural reference"]','{"slug": "veronica-speedwell", "common_name": "Veronica / Speedwell", "scientific_name": "Veronica spicata", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring or fall in well-drained soil; excellent drought tolerance once established."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Plant in well-drained soil in full sun; speedwell is notably drought-tolerant and performs poorly in soggy or heavy clay conditions. The upright spikes of blue, pink, or white flowers bloom from late spring into summer and are excellent for cutting. Deadhead by removing spent spikes back to a lateral bud or leaf to extend the flowering period and prevent excessive self-seeding. Divide every 3–4 years in early spring to maintain vigor and an attractive mounding habit.", "sources": ["general horticultural reference"]}')
