  VALUES ('wax-begonia','Wax Begonia','Begonia × semperflorens-cultorum','flower','annual',14,21,70,75,70,90,'transplant','indoor-start','warm','tender','last_frost',-12,-10,'Start indoors 10–12 weeks before last frost due to slow growth; transplant after frost danger has fully passed.',3,11,8,12,6,18,8,12,'partial','moderate','Sow dust-fine seed on the surface of moist, sterile starting mix under bright light — do not cover, as seed needs light to germinate. Start early as wax begonias are slow growers before transplant size. These self-cleaning plants rarely need deadheading, blooming continuously from spring through frost. Bronze-leaved cultivars tolerate more direct sun than green-leaved types.','["general horticultural reference"]','{"slug": "wax-begonia", "common_name": "Wax Begonia", "scientific_name": "Begonia × semperflorens-cultorum", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start indoors 10–12 weeks before last frost due to slow growth; transplant after frost danger has fully passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 8, "max": 12}, "sun": "partial", "water": "moderate", "directions": "Sow dust-fine seed on the surface of moist, sterile starting mix under bright light — do not cover, as seed needs light to germinate. Start early as wax begonias are slow growers before transplant size. These self-cleaning plants rarely need deadheading, blooming continuously from spring through frost. Bronze-leaved cultivars tolerate more direct sun than green-leaved types.", "sources": ["general horticultural reference"]}')
