  VALUES ('almond','Almond','Prunus dulcis','fruit','nut / stone fruit',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','half-hardy','spring',-4,0,'Plant bare-root trees in late winter before bud break; almonds bloom very early and need a frost-free spring.',7,9,180,240,144,240,144,216,'full','low','Almonds bloom earlier than almost any other tree fruit and are severely damaged by late spring frosts, which is why commercial production is limited to Mediterranean-type climates. Most varieties require a cross-pollinator — plant at least two compatible cultivars (Non-Pareil with Carmel or Price, for example). Trees thrive in well-drained, alkaline to neutral soils and are drought-tolerant once established. Harvest when the hulls split open and the shells dry and harden, typically in late summer; spread nuts to dry for two weeks before storing.','["general horticultural reference"]','{"slug": "almond", "common_name": "Almond", "scientific_name": "Prunus dulcis", "category": "fruit", "subcategory": "nut / stone fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter before bud break; almonds bloom very early and need a frost-free spring."}, "usda_zones": {"min": 7, "max": 9}, "spacing_in": {"min": 180, "max": 240}, "height_in": {"min": 144, "max": 240}, "spread_in": {"min": 144, "max": 216}, "sun": "full", "water": "low", "directions": "Almonds bloom earlier than almost any other tree fruit and are severely damaged by late spring frosts, which is why commercial production is limited to Mediterranean-type climates. Most varieties require a cross-pollinator — plant at least two compatible cultivars (Non-Pareil with Carmel or Price, for example). Trees thrive in well-drained, alkaline to neutral soils and are drought-tolerant once established. Harvest when the hulls split open and the shells dry and harden, typically in late summer; spread nuts to dry for two weeks before storing.", "sources": ["general horticultural reference"]}')
