  VALUES ('american-persimmon','American Persimmon','Diospyros virginiana','fruit','berry-like drupe',NULL,NULL,NULL,NULL,2190,3650,'transplant','transplant','perennial','hardy','spring',-2,2,'Plant in early spring; persimmons have a deep taproot so handle with care and disturb roots as little as possible.',4,9,180,360,180,480,120,300,'full','low','American persimmon is dioecious — male and female flowers occur on separate trees — so plant at least one of each for reliable fruiting, though some populations produce fruit without pollination. It is exceptionally cold-hardy and tolerant of poor soils, making it one of the easiest native fruit trees. Fruit is intensely astringent until fully ripe and soft, usually after the first hard freeze; pick after the flesh has turned translucent orange and jelly-soft. Little pruning is needed beyond removing dead or crossing wood.','["general horticultural reference"]','{"slug": "american-persimmon", "common_name": "American Persimmon", "scientific_name": "Diospyros virginiana", "category": "fruit", "subcategory": "berry-like drupe", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2190, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant in early spring; persimmons have a deep taproot so handle with care and disturb roots as little as possible."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 180, "max": 360}, "height_in": {"min": 180, "max": 480}, "spread_in": {"min": 120, "max": 300}, "sun": "full", "water": "low", "directions": "American persimmon is dioecious — male and female flowers occur on separate trees — so plant at least one of each for reliable fruiting, though some populations produce fruit without pollination. It is exceptionally cold-hardy and tolerant of poor soils, making it one of the easiest native fruit trees. Fruit is intensely astringent until fully ripe and soft, usually after the first hard freeze; pick after the flesh has turned translucent orange and jelly-soft. Little pruning is needed beyond removing dead or crossing wood.", "sources": ["general horticultural reference"]}')
