INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('apple','Apple','Malus domestica','fruit','pome fruit',NULL,NULL,NULL,NULL,730,1825,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring while still dormant, before buds break.',3,9,96,240,60,240,72,240,'full','moderate','Plant bare-root stock in well-drained soil, spreading roots carefully; stake dwarf trees for the first two seasons. Most varieties require a second cultivar nearby for cross-pollination — check chill-hour requirements to match your climate (600–1200 hours for standard types, under 400 for low-chill selections). Prune annually in late dormancy to an open-center or central-leader form to improve light penetration and air flow. Harvest when fruit separates with a gentle upward twist and seeds have turned brown, 2–5 years after planting.','["general horticultural reference"]','{"slug": "apple", "common_name": "Apple", "scientific_name": "Malus domestica", "category": "fruit", "subcategory": "pome fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring while still dormant, before buds break."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 96, "max": 240}, "height_in": {"min": 60, "max": 240}, "spread_in": {"min": 72, "max": 240}, "sun": "full", "water": "moderate", "directions": "Plant bare-root stock in well-drained soil, spreading roots carefully; stake dwarf trees for the first two seasons. Most varieties require a second cultivar nearby for cross-pollination — check chill-hour requirements to match your climate (600–1200 hours for standard types, under 400 for low-chill selections). Prune annually in late dormancy to an open-center or central-leader form to improve light penetration and air flow. Harvest when fruit separates with a gentle upward twist and seeds have turned brown, 2–5 years after planting.", "sources": ["general horticultural reference"]}')
