INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('asian-pear','Asian Pear','Pyrus pyrifolia','fruit','pome fruit',NULL,NULL,NULL,NULL,730,1825,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring; in mild-winter zones plant in fall.',5,9,96,180,120,180,96,180,'full','moderate','Asian pears ripen on the tree — unlike European pears they do not need post-harvest ripening — so taste-test for sweetness before picking. Most varieties are self-unfruitful and yield best with a second Asian pear or even a compatible European variety nearby. Chill requirements are moderate (450–700 hours), making many selections suitable for zones 5–9. Annual thinning of fruit clusters to one per spur prevents limb breakage and encourages larger, better-flavored fruit.','["general horticultural reference"]','{"slug": "asian-pear", "common_name": "Asian Pear", "scientific_name": "Pyrus pyrifolia", "category": "fruit", "subcategory": "pome fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring; in mild-winter zones plant in fall."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 96, "max": 180}, "height_in": {"min": 120, "max": 180}, "spread_in": {"min": 96, "max": 180}, "sun": "full", "water": "moderate", "directions": "Asian pears ripen on the tree — unlike European pears they do not need post-harvest ripening — so taste-test for sweetness before picking. Most varieties are self-unfruitful and yield best with a second Asian pear or even a compatible European variety nearby. Chill requirements are moderate (450–700 hours), making many selections suitable for zones 5–9. Annual thinning of fruit clusters to one per spur prevents limb breakage and encourages larger, better-flavored fruit.", "sources": ["general horticultural reference"]}')
