  VALUES ('english-walnut','English Walnut','Juglans regia','fruit','nut',NULL,NULL,NULL,NULL,1825,3650,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring; in mild-winter zones fall planting works well.',5,9,360,600,360,720,360,600,'full','moderate','English walnuts are monoecious — male (catkins) and female flowers occur on the same tree — and most cultivars are partially self-fertile, though a second tree improves yields. The tree produces juglone, a chemical that inhibits growth of many plants beneath its canopy; avoid planting near vegetables, berries, or sensitive ornamentals. Grafted Carpathian-strain trees are more cold-hardy and begin fruiting in 4–7 years; seedling trees may take 10+ years. Harvest in fall when hulls begin to crack and turn dark; remove husks promptly and cure nuts for 2–3 weeks before storing.','["general horticultural reference"]','{"slug": "english-walnut", "common_name": "English Walnut", "scientific_name": "Juglans regia", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring; in mild-winter zones fall planting works well."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 360, "max": 600}, "height_in": {"min": 360, "max": 720}, "spread_in": {"min": 360, "max": 600}, "sun": "full", "water": "moderate", "directions": "English walnuts are monoecious — male (catkins) and female flowers occur on the same tree — and most cultivars are partially self-fertile, though a second tree improves yields. The tree produces juglone, a chemical that inhibits growth of many plants beneath its canopy; avoid planting near vegetables, berries, or sensitive ornamentals. Grafted Carpathian-strain trees are more cold-hardy and begin fruiting in 4–7 years; seedling trees may take 10+ years. Harvest in fall when hulls begin to crack and turn dark; remove husks promptly and cure nuts for 2–3 weeks before storing.", "sources": ["general horticultural reference"]}')
