  VALUES ('grapefruit','Grapefruit','Citrus paradisi','fruit','citrus',NULL,NULL,NULL,NULL,1460,2555,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant in spring after frost risk has passed; requires the longest, hottest growing season of any common citrus.',9,11,180,300,144,300,144,240,'full','moderate','Grapefruit is self-fertile and produces best in the warmest citrus climates — the prolonged heat of south Texas and southern California delivers better sugar development than coastal or inland zones 9. Trees are large and vigorous; allow 20–25 feet between them and avoid overcrowding with other trees. Ruby Red and Flame are popular pink-fleshed varieties with good cold tolerance for zone 9. Fruit takes 12–18 months from bloom to full ripeness; taste-test from late autumn onward — the peel may remain slightly greenish even when the juice is sweet.','["general horticultural reference"]','{"slug": "grapefruit", "common_name": "Grapefruit", "scientific_name": "Citrus paradisi", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after frost risk has passed; requires the longest, hottest growing season of any common citrus."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 180, "max": 300}, "height_in": {"min": 144, "max": 300}, "spread_in": {"min": 144, "max": 240}, "sun": "full", "water": "moderate", "directions": "Grapefruit is self-fertile and produces best in the warmest citrus climates — the prolonged heat of south Texas and southern California delivers better sugar development than coastal or inland zones 9. Trees are large and vigorous; allow 20–25 feet between them and avoid overcrowding with other trees. Ruby Red and Flame are popular pink-fleshed varieties with good cold tolerance for zone 9. Fruit takes 12–18 months from bloom to full ripeness; taste-test from late autumn onward — the peel may remain slightly greenish even when the juice is sweet.", "sources": ["general horticultural reference"]}')
