  VALUES ('hazelnut','Hazelnut / Filbert','Corylus avellana','fruit','nut',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root shrubs/trees in late winter to early spring; hazelnuts establish readily and tolerate a range of soils.',4,9,96,180,96,240,96,180,'full','moderate','Hazelnuts require cross-pollination and are wind-pollinated, so plant at least two different cultivars within 20 feet of each other; pollen is shed in late winter before leaves emerge. American hazelnut (C. americana) is hardier and more disease-resistant than European types; many gardeners grow hybrid selections for both traits. Eastern filbert blight (Anisogramma anomala) is a serious fungal disease in the eastern United States — choose blight-resistant cultivars such as Jefferson or York for eastern plantings. Harvest in late summer when nuts begin to fall from the husks on their own.','["general horticultural reference"]','{"slug": "hazelnut", "common_name": "Hazelnut / Filbert", "scientific_name": "Corylus avellana", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root shrubs/trees in late winter to early spring; hazelnuts establish readily and tolerate a range of soils."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 96, "max": 180}, "height_in": {"min": 96, "max": 240}, "spread_in": {"min": 96, "max": 180}, "sun": "full", "water": "moderate", "directions": "Hazelnuts require cross-pollination and are wind-pollinated, so plant at least two different cultivars within 20 feet of each other; pollen is shed in late winter before leaves emerge. American hazelnut (C. americana) is hardier and more disease-resistant than European types; many gardeners grow hybrid selections for both traits. Eastern filbert blight (Anisogramma anomala) is a serious fungal disease in the eastern United States — choose blight-resistant cultivars such as Jefferson or York for eastern plantings. Harvest in late summer when nuts begin to fall from the husks on their own.", "sources": ["general horticultural reference"]}')
