  VALUES ('kumquat','Kumquat','Fortunella margarita','fruit','citrus',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','half-hardy','last_frost',2,8,'Plant in spring; kumquats are the hardiest citrus relative and tolerate brief dips to 18°F.',8,11,72,144,72,144,60,120,'full','moderate','Kumquats are the hardiest of the citrus family and the only ones whose entire fruit — sweet peel and tangy flesh — is eaten whole. They are self-fertile and well-suited to container growing in zones 7–8, where they can be overwintered indoors. Unlike other citrus, kumquats go dormant more readily in winter, which improves their cold hardiness. Fruit ripens from late autumn through winter; harvest when fully orange and sweet-peel is prominent.','["general horticultural reference"]','{"slug": "kumquat", "common_name": "Kumquat", "scientific_name": "Fortunella margarita", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring; kumquats are the hardiest citrus relative and tolerate brief dips to 18°F."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 72, "max": 144}, "height_in": {"min": 72, "max": 144}, "spread_in": {"min": 60, "max": 120}, "sun": "full", "water": "moderate", "directions": "Kumquats are the hardiest of the citrus family and the only ones whose entire fruit — sweet peel and tangy flesh — is eaten whole. They are self-fertile and well-suited to container growing in zones 7–8, where they can be overwintered indoors. Unlike other citrus, kumquats go dormant more readily in winter, which improves their cold hardiness. Fruit ripens from late autumn through winter; harvest when fully orange and sweet-peel is prominent.", "sources": ["general horticultural reference"]}')
