  VALUES ('lime','Lime','Citrus aurantiifolia','fruit','citrus',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant in spring after all frost risk has passed; limes are the most cold-sensitive citrus.',10,11,96,180,72,180,72,144,'full','moderate','Key lime (C. aurantiifolia) is the most cold-sensitive common citrus and is reliable only in zones 10–11; Persian lime (C. latifolia) is somewhat hardier and suits zone 9 in sheltered spots. Both are self-fertile and produce almost continuously in warm climates with adequate water. Container culture in a large pot (25+ gallons) allows limes to be grown farther north and moved indoors during frost. Fruit is best harvested while still green and fully sized — if left to yellow on the tree it becomes dry and flavorless.','["general horticultural reference"]','{"slug": "lime", "common_name": "Lime", "scientific_name": "Citrus aurantiifolia", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after all frost risk has passed; limes are the most cold-sensitive citrus."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 96, "max": 180}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 72, "max": 144}, "sun": "full", "water": "moderate", "directions": "Key lime (C. aurantiifolia) is the most cold-sensitive common citrus and is reliable only in zones 10–11; Persian lime (C. latifolia) is somewhat hardier and suits zone 9 in sheltered spots. Both are self-fertile and produce almost continuously in warm climates with adequate water. Container culture in a large pot (25+ gallons) allows limes to be grown farther north and moved indoors during frost. Fruit is best harvested while still green and fully sized — if left to yellow on the tree it becomes dry and flavorless.", "sources": ["general horticultural reference"]}')
