INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('nectarine','Nectarine','Prunus persica var. nucipersica','fruit','stone fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','half-hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring before bud break.',5,9,144,216,120,192,120,192,'full','moderate','Nectarines are essentially smooth-skinned peaches and share the same culture — self-fertile, open-center pruning, and annual heading-back of one-year-old wood. Because nectarines lack the peach''s fuzzy skin barrier they are somewhat more susceptible to brown rot and bacterial spot in humid climates, so good air circulation is critical. Chill requirements range from 250 to 900 hours depending on cultivar; select accordingly. Fruit is ready when it gives slightly to thumb pressure and the background color has shifted from green to creamy yellow.','["general horticultural reference"]','{"slug": "nectarine", "common_name": "Nectarine", "scientific_name": "Prunus persica var. nucipersica", "category": "fruit", "subcategory": "stone fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring before bud break."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 144, "max": 216}, "height_in": {"min": 120, "max": 192}, "spread_in": {"min": 120, "max": 192}, "sun": "full", "water": "moderate", "directions": "Nectarines are essentially smooth-skinned peaches and share the same culture — self-fertile, open-center pruning, and annual heading-back of one-year-old wood. Because nectarines lack the peach''s fuzzy skin barrier they are somewhat more susceptible to brown rot and bacterial spot in humid climates, so good air circulation is critical. Chill requirements range from 250 to 900 hours depending on cultivar; select accordingly. Fruit is ready when it gives slightly to thumb pressure and the background color has shifted from green to creamy yellow.", "sources": ["general horticultural reference"]}')
