INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('peach','Peach','Prunus persica','fruit','stone fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','half-hardy','spring',-4,0,'Plant bare-root trees in late winter before bud swell; in zones 8–9 fall planting is also successful.',5,9,144,216,120,192,120,192,'full','moderate','Most peaches are self-fertile, so a single tree will produce fruit, but they need 600–1000 chill hours — choose low-chill varieties (below 400 hours) for zones 8–9. Train to an open-center (vase) shape to allow sunlight deep into the canopy, and prune out about one-third of last year''s growth each dormant season because peaches only fruit on one-year-old wood. Thin fruit to 6–8 inches apart after June drop to size up remaining fruit and reduce limb breakage. Harvest when the green ground color fades to cream and the fruit yields to gentle pressure.','["general horticultural reference"]','{"slug": "peach", "common_name": "Peach", "scientific_name": "Prunus persica", "category": "fruit", "subcategory": "stone fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter before bud swell; in zones 8–9 fall planting is also successful."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 144, "max": 216}, "height_in": {"min": 120, "max": 192}, "spread_in": {"min": 120, "max": 192}, "sun": "full", "water": "moderate", "directions": "Most peaches are self-fertile, so a single tree will produce fruit, but they need 600–1000 chill hours — choose low-chill varieties (below 400 hours) for zones 8–9. Train to an open-center (vase) shape to allow sunlight deep into the canopy, and prune out about one-third of last year''s growth each dormant season because peaches only fruit on one-year-old wood. Thin fruit to 6–8 inches apart after June drop to size up remaining fruit and reduce limb breakage. Harvest when the green ground color fades to cream and the fruit yields to gentle pressure.", "sources": ["general horticultural reference"]}')
