INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pear','Pear','Pyrus communis','fruit','pome fruit',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring while dormant; fall planting works in zones 7–9.',4,9,120,240,120,240,96,180,'full','moderate','European pears require 700–1200 chill hours and almost always need a second compatible cultivar for adequate pollination; Bosc and Anjou cross well with each other. Pears are prone to fire blight, so choose resistant varieties and prune out any infected wood well below the canker margin. Train to a central leader and avoid excess nitrogen, which promotes lush growth susceptible to blight. Pick pears while still firm and ripen indoors at room temperature — they go mealy if left on the tree too long.','["general horticultural reference"]','{"slug": "pear", "common_name": "Pear", "scientific_name": "Pyrus communis", "category": "fruit", "subcategory": "pome fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring while dormant; fall planting works in zones 7–9."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 96, "max": 180}, "sun": "full", "water": "moderate", "directions": "European pears require 700–1200 chill hours and almost always need a second compatible cultivar for adequate pollination; Bosc and Anjou cross well with each other. Pears are prone to fire blight, so choose resistant varieties and prune out any infected wood well below the canker margin. Train to a central leader and avoid excess nitrogen, which promotes lush growth susceptible to blight. Pick pears while still firm and ripen indoors at room temperature — they go mealy if left on the tree too long.", "sources": ["general horticultural reference"]}')
