INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pomegranate','Pomegranate','Punica granatum','fruit','berry',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','half-hardy','last_frost',0,4,'Plant in spring after the last frost; in zones 9–11 fall planting is also suitable.',7,11,120,216,60,180,60,180,'full','low','Pomegranates are self-fertile and thrive in hot, dry conditions with well-drained soil; they tolerate drought but produce sweeter, larger fruit with regular deep watering from bloom through harvest. In zone 7, mulch the root zone heavily and site against a south-facing wall to protect against winter kill. Allow plants to develop as a multi-stemmed shrub or train to a single trunk by removing suckers. Fruit is ready in fall when it turns deep red, sounds hollow when tapped, and the crown (calyx) is prominent.','["general horticultural reference"]','{"slug": "pomegranate", "common_name": "Pomegranate", "scientific_name": "Punica granatum", "category": "fruit", "subcategory": "berry", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after the last frost; in zones 9–11 fall planting is also suitable."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 120, "max": 216}, "height_in": {"min": 60, "max": 180}, "spread_in": {"min": 60, "max": 180}, "sun": "full", "water": "low", "directions": "Pomegranates are self-fertile and thrive in hot, dry conditions with well-drained soil; they tolerate drought but produce sweeter, larger fruit with regular deep watering from bloom through harvest. In zone 7, mulch the root zone heavily and site against a south-facing wall to protect against winter kill. Allow plants to develop as a multi-stemmed shrub or train to a single trunk by removing suckers. Fruit is ready in fall when it turns deep red, sounds hollow when tapped, and the crown (calyx) is prominent.", "sources": ["general horticultural reference"]}')
