  VALUES ('sweet-cherry','Sweet Cherry','Prunus avium','fruit','stone fruit',NULL,NULL,NULL,NULL,1460,2555,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring before buds swell.',5,7,180,360,180,360,180,300,'full','moderate','Sweet cherries require 700–1100 chill hours and are among the least self-fertile of the stone fruits — always plant at least two compatible varieties, choosing cultivars from the same incompatibility group (or self-fertile types such as Stella and Lapins). They prefer well-drained, slightly alkaline soil and dislike wet feet, which promotes root rot and crown rot. Protect ripening fruit with bird netting. Harvest when fruit is deeply colored, fully sweet, and the stem parts cleanly from the spur.','["general horticultural reference"]','{"slug": "sweet-cherry", "common_name": "Sweet Cherry", "scientific_name": "Prunus avium", "category": "fruit", "subcategory": "stone fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring before buds swell."}, "usda_zones": {"min": 5, "max": 7}, "spacing_in": {"min": 180, "max": 360}, "height_in": {"min": 180, "max": 360}, "spread_in": {"min": 180, "max": 300}, "sun": "full", "water": "moderate", "directions": "Sweet cherries require 700–1100 chill hours and are among the least self-fertile of the stone fruits — always plant at least two compatible varieties, choosing cultivars from the same incompatibility group (or self-fertile types such as Stella and Lapins). They prefer well-drained, slightly alkaline soil and dislike wet feet, which promotes root rot and crown rot. Protect ripening fruit with bird netting. Harvest when fruit is deeply colored, fully sweet, and the stem parts cleanly from the spur.", "sources": ["general horticultural reference"]}')
