INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('anise','Anise','Pimpinella anisum','herb','annual',7,14,60,70,100,120,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or just after last frost; anise dislikes transplanting and needs a long, warm season.',4,9,6,12,18,24,6,9,'full','moderate','Sow seeds 1/4 in deep directly in their final location in rich, well-drained soil; anise develops a taproot that transplants poorly. Thin to 6–12 in apart once seedlings are established, and stake plants in exposed sites as they can be top-heavy when in flower. Anise needs a long, frost-free season to set seed—at least 120 days—so start as early as possible in cool climates. Harvest umbels when seeds begin to turn gray-green, cutting whole heads into paper bags to catch seeds as they ripen.','["general horticultural reference"]','{"slug": "anise", "common_name": "Anise", "scientific_name": "Pimpinella anisum", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 100, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or just after last frost; anise dislikes transplanting and needs a long, warm season."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep directly in their final location in rich, well-drained soil; anise develops a taproot that transplants poorly. Thin to 6–12 in apart once seedlings are established, and stake plants in exposed sites as they can be top-heavy when in flower. Anise needs a long, frost-free season to set seed—at least 120 days—so start as early as possible in cool climates. Harvest umbels when seeds begin to turn gray-green, cutting whole heads into paper bags to catch seeds as they ripen.", "sources": ["general horticultural reference"]}')
