  VALUES ('anise-hyssop','Anise Hyssop','Agastache foeniculum','herb','aromatic perennial',7,14,65,75,80,100,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow as seeds prefer light for germination.',4,9,18,24,24,48,18,24,'full','low','Press tiny seeds onto the surface of moist starting mix without covering; keep warm at 70°F until sprouts appear. Plants are drought-tolerant once established and perform well in average to poor soil with good drainage. Harvest leaves throughout the growing season for anise-scented teas and culinary use; the edible flowers attract bees and butterflies prolifically. Allow some spikes to go to seed in autumn for natural self-sowing or collect seed for the following year.','["general horticultural reference"]','{"slug": "anise-hyssop", "common_name": "Anise Hyssop", "scientific_name": "Agastache foeniculum", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow as seeds prefer light for germination."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Press tiny seeds onto the surface of moist starting mix without covering; keep warm at 70°F until sprouts appear. Plants are drought-tolerant once established and perform well in average to poor soil with good drainage. Harvest leaves throughout the growing season for anise-scented teas and culinary use; the edible flowers attract bees and butterflies prolifically. Allow some spikes to go to seed in autumn for natural self-sowing or collect seed for the following year.", "sources": ["general horticultural reference"]}')
