INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('basil','Basil','Ocimum basilicum','herb','annual',5,10,65,85,60,90,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant only after nights stay reliably above 50°F.',2,11,12,18,12,24,12,18,'full','moderate','Sow seeds 1/4 in deep in a warm, moist seed-starting mix and keep soil above 65°F for reliable sprouting. Pinch out flower buds as soon as they appear to encourage bushy leaf production and delay bolting. Water at the base to avoid fungal spots, and feed lightly with a balanced fertilizer mid-season. Harvest by snipping stems just above a leaf node once plants have at least six true leaves.','["general horticultural reference"]','{"slug": "basil", "common_name": "Basil", "scientific_name": "Ocimum basilicum", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant only after nights stay reliably above 50°F."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in a warm, moist seed-starting mix and keep soil above 65°F for reliable sprouting. Pinch out flower buds as soon as they appear to encourage bushy leaf production and delay bolting. Water at the base to avoid fungal spots, and feed lightly with a balanced fertilizer mid-season. Harvest by snipping stems just above a leaf node once plants have at least six true leaves.", "sources": ["general horticultural reference"]}')
