  VALUES ('bay-laurel','Bay Laurel','Laurus nobilis','herb','perennial',30,60,60,70,365,730,'transplant','cutting','perennial','half-hardy','last_frost',0,4,'Plant rooted cuttings or established transplants after last frost in spring.',8,11,48,72,48,240,36,120,'full','low','Take semi-ripe stem cuttings in summer, dip in rooting hormone, and insert into gritty propagating mix; expect rooting in 6–9 weeks. Plant in well-drained soil in a sheltered, sunny site; in zones 7 and colder, grow in containers that can be moved indoors before hard frost. Clip the canopy to shape annually and remove any reverted plain shoots from variegated forms. Harvest individual leaves as needed once the plant is established; leaves are most pungent when dried for 1–2 weeks.','["general horticultural reference"]','{"slug": "bay-laurel", "common_name": "Bay Laurel", "scientific_name": "Laurus nobilis", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 30, "max": 60}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings or established transplants after last frost in spring."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 48, "max": 240}, "spread_in": {"min": 36, "max": 120}, "sun": "full", "water": "low", "directions": "Take semi-ripe stem cuttings in summer, dip in rooting hormone, and insert into gritty propagating mix; expect rooting in 6–9 weeks. Plant in well-drained soil in a sheltered, sunny site; in zones 7 and colder, grow in containers that can be moved indoors before hard frost. Clip the canopy to shape annually and remove any reverted plain shoots from variegated forms. Harvest individual leaves as needed once the plant is established; leaves are most pungent when dried for 1–2 weeks.", "sources": ["general horticultural reference"]}')
