INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('blue-vervain','Blue Vervain','Verbena hastata','herb','medicinal perennial',14,30,55,65,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; cold-moist stratification for 4–6 weeks significantly improves germination of this native species.',3,9,18,24,36,60,18,24,'full','high','Cold-stratify seeds for 4–6 weeks in the refrigerator before surface-sowing onto warm starting mix; germination is erratic without this treatment. Blue vervain is a native North American wetland plant that thrives in consistently moist to wet soil along streams, pond margins, or rain gardens. Harvest aerial parts — leafy stems and the distinctive candelabra-like flower spikes — when in bloom through summer, tincing in alcohol for use as a traditional nervine for tension and anxiety. Plants self-seed freely in moist conditions and will naturalize into attractive wildlife-supporting stands over time.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "blue-vervain", "common_name": "Blue Vervain", "scientific_name": "Verbena hastata", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; cold-moist stratification for 4–6 weeks significantly improves germination of this native species."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "high", "directions": "Cold-stratify seeds for 4–6 weeks in the refrigerator before surface-sowing onto warm starting mix; germination is erratic without this treatment. Blue vervain is a native North American wetland plant that thrives in consistently moist to wet soil along streams, pond margins, or rain gardens. Harvest aerial parts — leafy stems and the distinctive candelabra-like flower spikes — when in bloom through summer, tincing in alcohol for use as a traditional nervine for tension and anxiety. Plants self-seed freely in moist conditions and will naturalize into attractive wildlife-supporting stands over time.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
