INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('caraway','Caraway','Carum carvi','herb','biennial',10,21,50,70,365,540,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; caraway is biennial and flowers in its second year.',3,8,6,9,18,24,6,9,'full','moderate','Sow seeds 1/4 in deep in deep, loose, well-drained soil; caraway has a fleshy taproot and dislikes waterlogged conditions. As a biennial, it produces a rosette of ferny leaves in the first year, then flowers and sets seed in the second before dying. Thin to 6–9 in once seedlings are established and keep the bed weed-free. Harvest seed heads when they turn brown, cutting into bags to catch the aromatic seeds before they shatter.','["general horticultural reference"]','{"slug": "caraway", "common_name": "Caraway", "scientific_name": "Carum carvi", "category": "herb", "subcategory": "biennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 70}, "days_to_maturity": {"min": 365, "max": 540}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; caraway is biennial and flowers in its second year."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in deep, loose, well-drained soil; caraway has a fleshy taproot and dislikes waterlogged conditions. As a biennial, it produces a rosette of ferny leaves in the first year, then flowers and sets seed in the second before dying. Thin to 6–9 in once seedlings are established and keep the bed weed-free. Harvest seed heads when they turn brown, cutting into bags to catch the aromatic seeds before they shatter.", "sources": ["general horticultural reference"]}')
