INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('comfrey','Comfrey','Symphytum officinale','herb','medicinal perennial',14,21,55,65,90,120,'transplant','division','perennial','hardy','last_frost',-4,2,'Plant root cuttings or crown divisions in early spring; even small root fragments will regenerate into new plants so choose the planting site carefully.',3,9,24,36,24,48,24,36,'partial','moderate','Propagate from 2–4 in root cuttings planted horizontally 2–3 in deep; plants grow vigorously and are nearly impossible to eradicate once established, so site them permanently. Mulch heavily around plants and cut back to the ground two or three times per growing season to harvest the biomass-rich leaves as a liquid fertilizer or compost activator. Leaves can also be processed into poultice form for topical soothing use on bruises and minor sprains. Note that internal use is not recommended due to pyrrolizidine alkaloid content.','["general horticultural reference", "RHS Plant Guides"]','{"slug": "comfrey", "common_name": "Comfrey", "scientific_name": "Symphytum officinale", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 2}, "note": "Plant root cuttings or crown divisions in early spring; even small root fragments will regenerate into new plants so choose the planting site carefully."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Propagate from 2–4 in root cuttings planted horizontally 2–3 in deep; plants grow vigorously and are nearly impossible to eradicate once established, so site them permanently. Mulch heavily around plants and cut back to the ground two or three times per growing season to harvest the biomass-rich leaves as a liquid fertilizer or compost activator. Leaves can also be processed into poultice form for topical soothing use on bruises and minor sprains. Note that internal use is not recommended due to pyrrolizidine alkaloid content.", "sources": ["general horticultural reference", "RHS Plant Guides"]}')
