INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mullein','Common Mullein','Verbascum thapsus','herb','medicinal biennial',12,15,60,70,365,548,'seed','direct','perennial','hardy','last_frost',-4,0,'Direct sow in early spring or summer; biennial plants form a rosette the first year and flower the second year.',3,9,18,24,36,84,24,36,'full','low','Scatter tiny seeds on bare, disturbed soil and do not cover — they need light to germinate; thin to 18–24 in apart once seedlings are established. As a biennial, mullein forms a large, velvety rosette of leaves in the first year before sending up a tall flower spike in its second season. First-year leaves are harvested and dried for use in respiratory-support teas and smoking blends; flowers are gathered as they open along the stalk, often infused into olive oil for ear-drop preparations. Allow the towering flower spike to set seed for reliable self-sowing in subsequent years.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "mullein", "common_name": "Common Mullein", "scientific_name": "Verbascum thapsus", "category": "herb", "subcategory": "medicinal biennial", "days_to_germination": {"min": 12, "max": 15}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow in early spring or summer; biennial plants form a rosette the first year and flower the second year."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 84}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Scatter tiny seeds on bare, disturbed soil and do not cover — they need light to germinate; thin to 18–24 in apart once seedlings are established. As a biennial, mullein forms a large, velvety rosette of leaves in the first year before sending up a tall flower spike in its second season. First-year leaves are harvested and dried for use in respiratory-support teas and smoking blends; flowers are gathered as they open along the stalk, often infused into olive oil for ear-drop preparations. Allow the towering flower spike to set seed for reliable self-sowing in subsequent years.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
