INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cumin','Cumin','Cuminum cyminum','herb','annual',7,14,65,85,90,120,'seed','indoor-start','warm','tender','last_frost',-4,-2,'Start indoors 4–6 weeks before last frost and transplant carefully after soil warms; cumin needs a long hot season.',5,10,4,6,12,24,4,6,'full','low','Start seeds indoors 4–6 weeks before last frost in deep cells to minimize taproot disturbance, sowing 1/4 in deep and keeping soil at 70°F or above. Transplant with great care, disturbing roots as little as possible, into sandy or well-drained soil in full sun. Cumin thrives in hot, dry conditions and performs poorly in cool, wet summers; mulch to retain ground warmth. Harvest umbels when seeds turn brown, drying the cut heads in a warm, airy spot before threshing out the pungent seeds.','["general horticultural reference"]','{"slug": "cumin", "common_name": "Cumin", "scientific_name": "Cuminum cyminum", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Start indoors 4–6 weeks before last frost and transplant carefully after soil warms; cumin needs a long hot season."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "low", "directions": "Start seeds indoors 4–6 weeks before last frost in deep cells to minimize taproot disturbance, sowing 1/4 in deep and keeping soil at 70°F or above. Transplant with great care, disturbing roots as little as possible, into sandy or well-drained soil in full sun. Cumin thrives in hot, dry conditions and performs poorly in cool, wet summers; mulch to retain ground warmth. Harvest umbels when seeds turn brown, drying the cut heads in a warm, airy spot before threshing out the pungent seeds.", "sources": ["general horticultural reference"]}')
