INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('dill','Dill','Anethum graveolens','herb','annual',7,14,60,75,40,60,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; succession-sow every 2–3 weeks for a continuous leaf harvest.',3,11,9,12,24,48,9,12,'full','moderate','Broadcast seeds thinly over a weed-free bed and cover with 1/8 in of soil, firming gently; dill needs light to germinate well. Avoid transplanting—the long taproot is easily damaged. Stake tall plants if the site is windy, and keep irrigation steady to delay the rush to flower. Snip feathery fronds once the plant has at least five leaf sets; for seed, allow umbels to go fully brown before cutting.','["general horticultural reference"]','{"slug": "dill", "common_name": "Dill", "scientific_name": "Anethum graveolens", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 75}, "days_to_maturity": {"min": 40, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; succession-sow every 2–3 weeks for a continuous leaf harvest."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Broadcast seeds thinly over a weed-free bed and cover with 1/8 in of soil, firming gently; dill needs light to germinate well. Avoid transplanting—the long taproot is easily damaged. Stake tall plants if the site is windy, and keep irrigation steady to delay the rush to flower. Snip feathery fronds once the plant has at least five leaf sets; for seed, allow umbels to go fully brown before cutting.", "sources": ["general horticultural reference"]}')
