  VALUES ('elecampane','Elecampane','Inula helenium','herb','medicinal perennial',14,21,60,70,540,730,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; a brief cold stratification of 2–3 weeks can improve germination.',3,8,24,36,60,96,36,48,'full','moderate','Sow seeds 1/4 in deep indoors after a brief cold stratification period; plants grow into impressive clumps by their second year, eventually reaching 6–8 feet tall. Plant in moist, deep, fertile soil as this large plant develops an extensive root system that benefits from ample space. Harvest the thick, inulin-rich roots in autumn of the second or third year, washing and slicing them before drying for respiratory-supportive preparations. The yellow daisy-like flowers appear in midsummer of the second year and are attractive to pollinators.','["general horticultural reference"]','{"slug": "elecampane", "common_name": "Elecampane", "scientific_name": "Inula helenium", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 540, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; a brief cold stratification of 2–3 weeks can improve germination."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 60, "max": 96}, "spread_in": {"min": 36, "max": 48}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep indoors after a brief cold stratification period; plants grow into impressive clumps by their second year, eventually reaching 6–8 feet tall. Plant in moist, deep, fertile soil as this large plant develops an extensive root system that benefits from ample space. Harvest the thick, inulin-rich roots in autumn of the second or third year, washing and slicing them before drying for respiratory-supportive preparations. The yellow daisy-like flowers appear in midsummer of the second year and are attractive to pollinators.", "sources": ["general horticultural reference"]}')
