INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lavender-english','English Lavender','Lavandula angustifolia','herb','aromatic perennial',14,28,65,70,90,200,'transplant','indoor-start','perennial','hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after frost danger has fully passed into well-drained, alkaline soil.',5,8,18,24,12,24,18,24,'full','low','Surface-sow seeds and keep barely moist; germination is slow and uneven, so starting from cuttings or divisions is often more reliable. Plant in fast-draining, lean soil — rich or wet conditions promote rot and weak growth. Prune plants back by about one-third after the first flush of blooms to keep growth compact and encourage a second flowering. Harvest flower spikes just as the buds begin to open, bundling and hanging upside down in a warm, airy space to dry for sachets, culinary use, and aromatherapy.','["general horticultural reference", "RHS Plant Guides"]','{"slug": "lavender-english", "common_name": "English Lavender", "scientific_name": "Lavandula angustifolia", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 90, "max": 200}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after frost danger has fully passed into well-drained, alkaline soil."}, "usda_zones": {"min": 5, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Surface-sow seeds and keep barely moist; germination is slow and uneven, so starting from cuttings or divisions is often more reliable. Plant in fast-draining, lean soil — rich or wet conditions promote rot and weak growth. Prune plants back by about one-third after the first flush of blooms to keep growth compact and encourage a second flowering. Harvest flower spikes just as the buds begin to open, bundling and hanging upside down in a warm, airy space to dry for sachets, culinary use, and aromatherapy.", "sources": ["general horticultural reference", "RHS Plant Guides"]}')
