  VALUES ('feverfew','Feverfew','Tanacetum parthenium','herb','medicinal perennial',10,14,65,72,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; press seeds onto the surface of the mix as they need light to germinate.',5,9,12,18,18,24,12,18,'full','moderate','Seeds are tiny and require light for germination — press them gently onto moist starting mix without covering. Once established, plants are quite drought-tolerant and spread readily by self-seeding. Shear plants back by half after flowering to maintain a tidy mound and encourage fresh foliage. The leaves are the medicinal part; harvest fresh leaves for tea or tincture — wear gloves as some people experience skin irritation from the foliage.','["general horticultural reference"]','{"slug": "feverfew", "common_name": "Feverfew", "scientific_name": "Tanacetum parthenium", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 72}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; press seeds onto the surface of the mix as they need light to germinate."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Seeds are tiny and require light for germination — press them gently onto moist starting mix without covering. Once established, plants are quite drought-tolerant and spread readily by self-seeding. Shear plants back by half after flowering to maintain a tidy mound and encourage fresh foliage. The leaves are the medicinal part; harvest fresh leaves for tea or tincture — wear gloves as some people experience skin irritation from the foliage.", "sources": ["general horticultural reference"]}')
