INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('garlic-chives','Garlic Chives','Allium tuberosum','herb','perennial',10,14,60,70,60,90,'seed','direct','perennial','hardy','last_frost',-6,-4,'Sow directly 4–6 weeks before last frost or transplant established divisions in spring.',3,9,8,12,12,20,9,12,'full','moderate','Sow seeds 1/4 in deep and keep soil moist; germination is similar to common chives but the flat, grass-like leaves have a distinct mild garlic flavor. Grow in well-drained, fertile soil and divide clumps every 2–3 years to prevent overcrowding and maintain productivity. Deadhead flowers promptly, as garlic chives self-seed prolifically and can become weedy. Harvest flat leaves at any height; older leaves become slightly tough but remain useful cooked.','["general horticultural reference"]','{"slug": "garlic-chives", "common_name": "Garlic Chives", "scientific_name": "Allium tuberosum", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Sow directly 4–6 weeks before last frost or transplant established divisions in spring."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 12, "max": 20}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep and keep soil moist; germination is similar to common chives but the flat, grass-like leaves have a distinct mild garlic flavor. Grow in well-drained, fertile soil and divide clumps every 2–3 years to prevent overcrowding and maintain productivity. Deadhead flowers promptly, as garlic chives self-seed prolifically and can become weedy. Harvest flat leaves at any height; older leaves become slightly tough but remain useful cooked.", "sources": ["general horticultural reference"]}')
