INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('goldenseal','Goldenseal','Hydrastis canadensis','herb','medicinal perennial',180,365,50,60,1460,2190,'seed','division','perennial','hardy','fall',-4,0,'Plant rhizome divisions in early autumn in a shaded woodland bed; seeds require prolonged double dormancy and are best left to experienced growers.',3,8,6,12,8,16,8,12,'shade','moderate','Plant small rhizome pieces 1–2 in deep in autumn in deep, shaded woodland soil rich in leaf mold; rhizome division is far more reliable than growing from seed. Goldenseal requires 70–80% shade and the moist, humus-rich, slightly acidic conditions of mature eastern North American forests — raised beds under deciduous trees work well. This is a slow-growing, at-risk native species; growing your own reduces pressure on wild populations, but expect 4–6 years before roots are substantial enough to harvest. Harvest small portions of the golden rhizome in autumn of the fourth or fifth year, leaving the majority of the root system intact for continued growth.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "goldenseal", "common_name": "Goldenseal", "scientific_name": "Hydrastis canadensis", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 180, "max": 365}, "germination_soil_temp_f": {"min": 50, "max": 60}, "days_to_maturity": {"min": 1460, "max": 2190}, "maturity_from": "seed", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant rhizome divisions in early autumn in a shaded woodland bed; seeds require prolonged double dormancy and are best left to experienced growers."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 8, "max": 16}, "spread_in": {"min": 8, "max": 12}, "sun": "shade", "water": "moderate", "directions": "Plant small rhizome pieces 1–2 in deep in autumn in deep, shaded woodland soil rich in leaf mold; rhizome division is far more reliable than growing from seed. Goldenseal requires 70–80% shade and the moist, humus-rich, slightly acidic conditions of mature eastern North American forests — raised beds under deciduous trees work well. This is a slow-growing, at-risk native species; growing your own reduces pressure on wild populations, but expect 4–6 years before roots are substantial enough to harvest. Harvest small portions of the golden rhizome in autumn of the fourth or fifth year, leaving the majority of the root system intact for continued growth.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
