INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('horehound','Horehound','Marrubium vulgare','herb','medicinal perennial',10,14,60,70,85,100,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow as seeds are small and benefit from light for germination.',3,9,12,18,12,24,12,18,'full','low','Surface-sow onto moist mix 6–8 weeks before transplanting; horehound germinates readily in warm soil but can be slow and erratic. Plant in dry, well-drained, even rocky or sandy soil where most plants would struggle — fertile, moist conditions cause leggy, weak growth. Harvest stems and leaves before flowering for the most potent bitterness, bundling for drying or infusing fresh into candy and cough syrups. Shear plants back in late summer to keep growth compact and prevent excessive self-seeding.','["general horticultural reference"]','{"slug": "horehound", "common_name": "Horehound", "scientific_name": "Marrubium vulgare", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow as seeds are small and benefit from light for germination."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow onto moist mix 6–8 weeks before transplanting; horehound germinates readily in warm soil but can be slow and erratic. Plant in dry, well-drained, even rocky or sandy soil where most plants would struggle — fertile, moist conditions cause leggy, weak growth. Harvest stems and leaves before flowering for the most potent bitterness, bundling for drying or infusing fresh into candy and cough syrups. Shear plants back in late summer to keep growth compact and prevent excessive self-seeding.", "sources": ["general horticultural reference"]}')
