INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lemon-balm','Lemon Balm','Melissa officinalis','herb','perennial',10,21,60,70,70,90,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after the last frost date.',4,9,18,24,18,36,18,24,'partial','moderate','Surface-sow seeds and press lightly into moist mix without covering; they need light and warmth to sprout. Plant in well-drained soil in partial shade, particularly in hot climates, to maintain fresh-looking, non-scorched foliage. Cut plants back by half after the first flush of growth and again after any flowering to encourage compact, leafy regrowth. Harvest leaves before the plant flowers for the strongest lemon fragrance, picking in the morning after dew has dried.','["general horticultural reference"]','{"slug": "lemon-balm", "common_name": "Lemon Balm", "scientific_name": "Melissa officinalis", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after the last frost date."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Surface-sow seeds and press lightly into moist mix without covering; they need light and warmth to sprout. Plant in well-drained soil in partial shade, particularly in hot climates, to maintain fresh-looking, non-scorched foliage. Cut plants back by half after the first flush of growth and again after any flowering to encourage compact, leafy regrowth. Harvest leaves before the plant flowers for the strongest lemon fragrance, picking in the morning after dew has dried.", "sources": ["general horticultural reference"]}')
