  VALUES ('milk-thistle','Milk Thistle','Silybum marianum','herb','medicinal annual/biennial',7,14,55,65,120,180,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; seeds germinate readily in cool soil and plants can handle light frost.',5,10,24,36,36,72,24,36,'full','low','Direct sow 1/4 in deep in early spring; milk thistle germinates readily in cool, moist conditions and self-seeds vigorously once established. Plants become quite large and spiny — space generously and wear gloves when tending them. Monitor flower heads closely as seeds ripen quickly and can be scattered by wind; harvest heads when the fluffy pappus begins to appear but before seeds fully disperse. Dry seed heads on a tray, then thresh to separate the hard achenes, which are ground or extracted for their silymarin content in liver-supportive preparations.','["general horticultural reference"]','{"slug": "milk-thistle", "common_name": "Milk Thistle", "scientific_name": "Silybum marianum", "category": "herb", "subcategory": "medicinal annual/biennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; seeds germinate readily in cool soil and plants can handle light frost."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Direct sow 1/4 in deep in early spring; milk thistle germinates readily in cool, moist conditions and self-seeds vigorously once established. Plants become quite large and spiny — space generously and wear gloves when tending them. Monitor flower heads closely as seeds ripen quickly and can be scattered by wind; harvest heads when the fluffy pappus begins to appear but before seeds fully disperse. Dry seed heads on a tray, then thresh to separate the hard achenes, which are ground or extracted for their silymarin content in liver-supportive preparations.", "sources": ["general horticultural reference"]}')
