INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('oregano','Oregano','Origanum vulgare','herb','perennial',7,14,65,75,80,90,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost and transplant after danger of frost has passed.',4,10,12,18,12,24,12,18,'full','low','Sow seeds on the surface of well-drained mix, pressing in lightly without covering since seeds need light to germinate. Plant in lean, gritty soil with excellent drainage; rich soil dilutes the essential oils that give oregano its pungency. Cut stems back by one-third after flowering to keep plants compact and productive. Harvest just as buds begin to open, when aromatic oil concentration is highest.','["general horticultural reference"]','{"slug": "oregano", "common_name": "Oregano", "scientific_name": "Origanum vulgare", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 80, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost and transplant after danger of frost has passed."}, "usda_zones": {"min": 4, "max": 10}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds on the surface of well-drained mix, pressing in lightly without covering since seeds need light to germinate. Plant in lean, gritty soil with excellent drainage; rich soil dilutes the essential oils that give oregano its pungency. Cut stems back by one-third after flowering to keep plants compact and productive. Harvest just as buds begin to open, when aromatic oil concentration is highest.", "sources": ["general horticultural reference"]}')
