  VALUES ('parsley','Parsley','Petroselinum crispum','herb','biennial',14,28,50,70,70,90,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow or start indoors 4–6 weeks before last frost; parsley tolerates light spring frosts once established.',3,11,6,9,10,18,6,12,'full','moderate','Soak seeds overnight to soften the hull, then sow 1/4 in deep; germination is notoriously slow—up to four weeks. Thin to 6–9 in and keep soil consistently moist, as parsley bolts quickly under drought stress. Apply a light nitrogen feed at mid-season to sustain lush leaf production. Harvest outer stems at the base, leaving the inner crown intact to keep the plant productive.','["general horticultural reference"]','{"slug": "parsley", "common_name": "Parsley", "scientific_name": "Petroselinum crispum", "category": "herb", "subcategory": "biennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 50, "max": 70}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow or start indoors 4–6 weeks before last frost; parsley tolerates light spring frosts once established."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 10, "max": 18}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Soak seeds overnight to soften the hull, then sow 1/4 in deep; germination is notoriously slow—up to four weeks. Thin to 6–9 in and keep soil consistently moist, as parsley bolts quickly under drought stress. Apply a light nitrogen feed at mid-season to sustain lush leaf production. Harvest outer stems at the base, leaving the inner crown intact to keep the plant productive.", "sources": ["general horticultural reference"]}')
