INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sage','Sage','Salvia officinalis','herb','perennial',10,21,60,70,75,100,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after frost has passed and soil is warm.',4,8,18,24,18,30,18,24,'full','low','Press seeds 1/8 in into well-drained seed mix and keep at 60–70°F; germination is steady but takes two to three weeks. Plant in sandy, well-drained soil in full sun; wet, poorly drained soil is the leading cause of sage death. Prune hard in early spring once new growth shows at the base to prevent the plant from becoming too woody. Harvest young leaves throughout the season, cutting stems back by no more than one-third at a time.','["general horticultural reference"]','{"slug": "sage", "common_name": "Sage", "scientific_name": "Salvia officinalis", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after frost has passed and soil is warm."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Press seeds 1/8 in into well-drained seed mix and keep at 60–70°F; germination is steady but takes two to three weeks. Plant in sandy, well-drained soil in full sun; wet, poorly drained soil is the leading cause of sage death. Prune hard in early spring once new growth shows at the base to prevent the plant from becoming too woody. Harvest young leaves throughout the season, cutting stems back by no more than one-third at a time.", "sources": ["general horticultural reference"]}')
