  VALUES ('spearmint','Spearmint','Mentha spicata','herb','perennial',NULL,NULL,NULL,NULL,60,90,'transplant','division','perennial','hardy','last_frost',-2,2,'Divide established clumps or transplant rooted runners in spring near the last frost date.',3,8,18,24,12,24,18,36,'partial','moderate','Set divisions in fertile, moisture-retentive soil, planting at the same depth they grew previously, and contain the root run with a buried barrier to prevent unwanted spread. Water regularly and avoid prolonged drought, which causes leaves to toughen and lose flavor. Cut stems back by half after each main harvest to stimulate a fresh flush of tender shoots. Harvest stems once they reach 6–8 in tall, taking no more than one-third of the plant at once.','["general horticultural reference"]','{"slug": "spearmint", "common_name": "Spearmint", "scientific_name": "Mentha spicata", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Divide established clumps or transplant rooted runners in spring near the last frost date."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Set divisions in fertile, moisture-retentive soil, planting at the same depth they grew previously, and contain the root run with a buried barrier to prevent unwanted spread. Water regularly and avoid prolonged drought, which causes leaves to toughen and lose flavor. Cut stems back by half after each main harvest to stimulate a fresh flush of tender shoots. Harvest stems once they reach 6–8 in tall, taking no more than one-third of the plant at once.", "sources": ["general horticultural reference"]}')
