INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('st-johns-wort','St. John''s Wort','Hypericum perforatum','herb','medicinal perennial',14,30,60,70,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow as seeds need light, and a 2–3 week cold-moist stratification period can improve germination rates.',3,8,18,24,18,36,18,24,'full','low','Surface-sow seeds onto moist mix; cold stratification for 2–3 weeks in the refrigerator prior to sowing can improve germination, especially with older seed. Plants thrive in poor, well-drained soil and become weedy in fertile conditions — resist the urge to fertilize. Harvest flower buds and newly opened blossoms around the summer solstice, when hypericin content peaks; rub a bud between your fingers and look for a red-purple stain confirming good potency. Dry flowers quickly on screens to preserve the active compounds.','["general horticultural reference"]','{"slug": "st-johns-wort", "common_name": "St. John''s Wort", "scientific_name": "Hypericum perforatum", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow as seeds need light, and a 2–3 week cold-moist stratification period can improve germination rates."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Surface-sow seeds onto moist mix; cold stratification for 2–3 weeks in the refrigerator prior to sowing can improve germination, especially with older seed. Plants thrive in poor, well-drained soil and become weedy in fertile conditions — resist the urge to fertilize. Harvest flower buds and newly opened blossoms around the summer solstice, when hypericin content peaks; rub a bud between your fingers and look for a red-purple stain confirming good potency. Dry flowers quickly on screens to preserve the active compounds.", "sources": ["general horticultural reference"]}')
