  VALUES ('stevia','Stevia','Stevia rebaudiana','herb','annual',7,14,68,78,90,120,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed.',9,11,18,24,18,36,12,18,'full','moderate','Sow seeds shallowly, just pressing them into moist seed-starting mix, as light aids germination; note that germination rates for stevia seed can be inconsistent. Transplant into well-drained, fertile soil after temperatures are reliably warm, and water consistently—stevia is sensitive to both drought and waterlogging. Pinch growing tips early to encourage a bushy form with more harvestable leaf area. Harvest leaves before the plant flowers, when glycoside content (sweetness) is at its peak; dry or use fresh.','["general horticultural reference"]','{"slug": "stevia", "common_name": "Stevia", "scientific_name": "Stevia rebaudiana", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 68, "max": 78}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds shallowly, just pressing them into moist seed-starting mix, as light aids germination; note that germination rates for stevia seed can be inconsistent. Transplant into well-drained, fertile soil after temperatures are reliably warm, and water consistently—stevia is sensitive to both drought and waterlogging. Pinch growing tips early to encourage a bushy form with more harvestable leaf area. Harvest leaves before the plant flowers, when glycoside content (sweetness) is at its peak; dry or use fresh.", "sources": ["general horticultural reference"]}')
