INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('stinging-nettle','Stinging Nettle','Urtica dioica','herb','medicinal perennial',10,14,55,65,60,90,'transplant','direct','perennial','hardy','last_frost',-4,0,'Direct sow in early spring as soon as soil is workable; surface-sow as seeds need light and cool temperatures to germinate.',3,10,18,24,24,60,18,36,'partial','moderate','Surface-sow onto moist, nitrogen-rich soil in a dedicated bed with underground barriers if possible, as nettles spread aggressively by rhizome. Always wear thick gloves and long sleeves when handling plants, as the hollow stinging hairs inject formic acid on contact. Harvest young growing tips in early spring before plants reach knee height, using them in soups, teas, and nutritive infusions — cooking or drying neutralizes the sting completely. Cut plants back to the ground two or three times per season to encourage fresh new growth throughout the year.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "stinging-nettle", "common_name": "Stinging Nettle", "scientific_name": "Urtica dioica", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow in early spring as soon as soil is workable; surface-sow as seeds need light and cool temperatures to germinate."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Surface-sow onto moist, nitrogen-rich soil in a dedicated bed with underground barriers if possible, as nettles spread aggressively by rhizome. Always wear thick gloves and long sleeves when handling plants, as the hollow stinging hairs inject formic acid on contact. Harvest young growing tips in early spring before plants reach knee height, using them in soups, teas, and nutritive infusions — cooking or drying neutralizes the sting completely. Cut plants back to the ground two or three times per season to encourage fresh new growth throughout the year.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
