INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('summer-savory','Summer Savory','Satureja hortensis','herb','annual',10,14,60,70,60,70,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or just after last frost once soil has warmed to 60°F.',3,11,6,9,12,18,6,9,'full','low','Press seeds lightly into the soil surface without covering, as they need light for good germination; thin seedlings to 6–9 in once they show two true leaves. Plant in full sun with very well-drained soil; summer savory tolerates lean soil and wilts under excess moisture. Pinch tips regularly to encourage branching and prevent early bolting in warm weather. Harvest whole stems just as flower buds begin to show for the best peppery flavor.','["general horticultural reference"]','{"slug": "summer-savory", "common_name": "Summer Savory", "scientific_name": "Satureja hortensis", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or just after last frost once soil has warmed to 60°F."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "low", "directions": "Press seeds lightly into the soil surface without covering, as they need light for good germination; thin seedlings to 6–9 in once they show two true leaves. Plant in full sun with very well-drained soil; summer savory tolerates lean soil and wilts under excess moisture. Pinch tips regularly to encourage branching and prevent early bolting in warm weather. Harvest whole stems just as flower buds begin to show for the best peppery flavor.", "sources": ["general horticultural reference"]}')
