INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('thyme','Thyme','Thymus vulgaris','herb','perennial',14,28,65,75,75,90,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; transplant after last frost when soil is warm.',4,9,9,12,6,12,12,16,'full','low','Surface-sow seeds under a thin layer of vermiculite and maintain warmth; germination is slow and irregular. Grow in fast-draining, slightly alkaline soil and avoid overwatering, which quickly leads to crown rot. Shear plants lightly in early spring to remove winter-killed wood and maintain a tidy mound. Harvest sprigs freely once plants are established; thyme''s flavor is most concentrated before flowers open.','["general horticultural reference"]','{"slug": "thyme", "common_name": "Thyme", "scientific_name": "Thymus vulgaris", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 75, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; transplant after last frost when soil is warm."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 12, "max": 16}, "sun": "full", "water": "low", "directions": "Surface-sow seeds under a thin layer of vermiculite and maintain warmth; germination is slow and irregular. Grow in fast-draining, slightly alkaline soil and avoid overwatering, which quickly leads to crown rot. Shear plants lightly in early spring to remove winter-killed wood and maintain a tidy mound. Harvest sprigs freely once plants are established; thyme''s flavor is most concentrated before flowers open.", "sources": ["general horticultural reference"]}')
