INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('valerian','Valerian','Valeriana officinalis','herb','medicinal perennial',14,21,55,65,150,180,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; seed viability drops quickly so use fresh seed and surface-sow as light aids germination.',4,9,18,24,48,72,24,36,'full','moderate','Use the freshest seed available, as viability declines within a year; surface-sow and keep cool and moist for best germination. Plants grow very tall in their second year and may need staking in windy locations; keep soil consistently moist and add compost annually. Remove flower heads in the first year to direct energy into root development. Harvest roots in the second autumn after the tops die back, washing and slicing them for drying; the characteristic musky odor intensifies as the root dries.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "valerian", "common_name": "Valerian", "scientific_name": "Valeriana officinalis", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 150, "max": 180}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; seed viability drops quickly so use fresh seed and surface-sow as light aids germination."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Use the freshest seed available, as viability declines within a year; surface-sow and keep cool and moist for best germination. Plants grow very tall in their second year and may need staking in windy locations; keep soil consistently moist and add compost annually. Remove flower heads in the first year to direct energy into root development. Harvest roots in the second autumn after the tops die back, washing and slicing them for drying; the characteristic musky odor intensifies as the root dries.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
