  VALUES ('wormwood','Wormwood','Artemisia absinthium','herb','aromatic perennial',10,21,60,70,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow as seeds need light and cool temperatures to germinate well.',3,8,18,24,24,48,18,30,'full','low','Surface-sow seeds under bright light at around 65°F; germination is often irregular so sow more densely than needed and thin later. Plant in lean, sharply drained soil — wormwood is extremely drought-tolerant and declines in wet or rich ground. The silvery foliage contains allelopathic compounds that can inhibit neighboring plants, so site it away from vegetables and herbs you want to thrive. Harvest leafy stems before or just as flowering begins for maximum bitterness, drying upside-down in bundles for use as a moth-deterring sachets or for absinthe production where legal.','["general horticultural reference"]','{"slug": "wormwood", "common_name": "Wormwood", "scientific_name": "Artemisia absinthium", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow as seeds need light and cool temperatures to germinate well."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Surface-sow seeds under bright light at around 65°F; germination is often irregular so sow more densely than needed and thin later. Plant in lean, sharply drained soil — wormwood is extremely drought-tolerant and declines in wet or rich ground. The silvery foliage contains allelopathic compounds that can inhibit neighboring plants, so site it away from vegetables and herbs you want to thrive. Harvest leafy stems before or just as flowering begins for maximum bitterness, drying upside-down in bundles for use as a moth-deterring sachets or for absinthe production where legal.", "sources": ["general horticultural reference"]}')
