  VALUES ('asparagus','Asparagus','Asparagus officinalis','vegetable','perennial',14,21,60,85,730,1095,'transplant','transplant','perennial','hardy','soil_workable',0,4,'Plant one-year-old crowns as soon as soil is workable in spring; dig 8-in-deep trenches and set crowns 18 in apart.',3,8,18,18,36,60,18,24,'full','moderate','Set one-year crowns in 8-in-deep trenches with roots spread over a ridge of compost, then gradually backfill as growth emerges. Do not harvest any spears in the first year and harvest lightly in year two to let the root system build strength. Beginning in year three, cut or snap spears at soil level when they are 6–8 in tall and before the tips begin to feather open. Stop harvesting after 4–6 weeks to allow ferns to grow and replenish the crown for the next season.','["general horticultural reference"]','{"slug": "asparagus", "common_name": "Asparagus", "scientific_name": "Asparagus officinalis", "category": "vegetable", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 85}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant one-year-old crowns as soon as soil is workable in spring; dig 8-in-deep trenches and set crowns 18 in apart."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 18}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Set one-year crowns in 8-in-deep trenches with roots spread over a ridge of compost, then gradually backfill as growth emerges. Do not harvest any spears in the first year and harvest lightly in year two to let the root system build strength. Beginning in year three, cut or snap spears at soil level when they are 6–8 in tall and before the tips begin to feather open. Stop harvesting after 4–6 weeks to allow ferns to grow and replenish the crown for the next season.", "sources": ["general horticultural reference"]}')
