INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('black-eyed-pea','Black-Eyed Pea','Vigna unguiculata','vegetable','legume',7,14,65,90,60,90,'seed','direct','warm','tender','last_frost',2,4,'Direct sow 2–4 weeks after last frost when soil is thoroughly warm; cowpeas are more heat- and drought-tolerant than common beans.',5,11,4,6,18,24,12,18,'full','low','Sow seeds 1 in deep in warm, well-drained soil; black-eyed peas tolerate poor, sandy soils and summer drought better than most vegetables. Avoid over-fertilizing with nitrogen, as they fix their own from the atmosphere. Harvest immature pods at 3–4 in for snap use, or allow pods to swell fully and turn pale tan for fresh shell peas; dry the remaining pods completely for storage as dried beans.','["general horticultural reference"]','{"slug": "black-eyed-pea", "common_name": "Black-Eyed Pea", "scientific_name": "Vigna unguiculata", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 90}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Direct sow 2–4 weeks after last frost when soil is thoroughly warm; cowpeas are more heat- and drought-tolerant than common beans."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1 in deep in warm, well-drained soil; black-eyed peas tolerate poor, sandy soils and summer drought better than most vegetables. Avoid over-fertilizing with nitrogen, as they fix their own from the atmosphere. Harvest immature pods at 3–4 in for snap use, or allow pods to swell fully and turn pale tan for fresh shell peas; dry the remaining pods completely for storage as dried beans.", "sources": ["general horticultural reference"]}')
