INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bok-choy','Bok Choy','Brassica rapa subsp. chinensis','vegetable','brassica',4,7,50,80,30,60,'seed','direct','cool','half-hardy','last_frost',-2,0,'Direct sow around last frost date in spring; for fall harvest, sow 6–8 weeks before first frost.',4,9,6,12,8,18,6,12,'full','moderate','Direct sow seed 1/4 in deep in fertile, moisture-retentive soil and thin to 6–12 in depending on whether you want baby or full-sized heads. Provide consistent moisture and feed lightly with nitrogen; drought stress and heat both trigger premature bolting. Harvest baby bok choy at 4–6 in tall by cutting at the soil line, or allow full-sized types to reach 12–18 in. The whole plant is edible—cut at the base and the plant may re-sprout for a second harvest.','["general horticultural reference"]','{"slug": "bok-choy", "common_name": "Bok Choy", "scientific_name": "Brassica rapa subsp. chinensis", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 30, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Direct sow around last frost date in spring; for fall harvest, sow 6–8 weeks before first frost."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 8, "max": 18}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Direct sow seed 1/4 in deep in fertile, moisture-retentive soil and thin to 6–12 in depending on whether you want baby or full-sized heads. Provide consistent moisture and feed lightly with nitrogen; drought stress and heat both trigger premature bolting. Harvest baby bok choy at 4–6 in tall by cutting at the soil line, or allow full-sized types to reach 12–18 in. The whole plant is edible—cut at the base and the plant may re-sprout for a second harvest.", "sources": ["general horticultural reference"]}')
