INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('broccoli','Broccoli','Brassica oleracea var. italica','vegetable','brassica',5,10,45,85,60,80,'transplant','indoor-start','cool','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant 2–4 weeks before last frost once seedlings are stocky.',3,10,18,24,18,36,18,24,'full','moderate','Sow seed 1/4 in deep in starter mix and keep at 70–75°F until germination, then grow on in bright light to prevent leggy transplants. Set out 2–4 weeks before last frost and fertilize with a nitrogen-rich feed at planting and again when heads begin to form. Harvest the central head while florets are still tight and dark green, before any yellow shows. Cut with a few inches of stem to encourage side-shoot production after the main head is removed.','["general horticultural reference"]','{"slug": "broccoli", "common_name": "Broccoli", "scientific_name": "Brassica oleracea var. italica", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant 2–4 weeks before last frost once seedlings are stocky."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in starter mix and keep at 70–75°F until germination, then grow on in bright light to prevent leggy transplants. Set out 2–4 weeks before last frost and fertilize with a nitrogen-rich feed at planting and again when heads begin to form. Harvest the central head while florets are still tight and dark green, before any yellow shows. Cut with a few inches of stem to encourage side-shoot production after the main head is removed.", "sources": ["general horticultural reference"]}')
