INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('brussels-sprouts','Brussels Sprouts','Brassica oleracea var. gemmifera','vegetable','brassica',5,10,45,85,80,100,'transplant','indoor-start','cool','hardy','first_frost',-18,-14,'Start indoors 14–18 weeks before first fall frost so plants mature in cool autumn weather.',3,9,18,24,24,36,18,24,'full','moderate','Sow 1/4 in deep indoors under bright lights; transplant into deeply prepared soil and stake tall plants against wind. When sprouts at the base reach marble size, remove the growing tip (topping) to concentrate energy and speed maturation of the remaining sprouts. Harvest sprouts from the bottom of the stalk upward once they are 1–2 in across and tight. Flavor peaks after exposure to a hard frost.','["general horticultural reference"]','{"slug": "brussels-sprouts", "common_name": "Brussels Sprouts", "scientific_name": "Brassica oleracea var. gemmifera", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -18, "max": -14}, "note": "Start indoors 14–18 weeks before first fall frost so plants mature in cool autumn weather."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow 1/4 in deep indoors under bright lights; transplant into deeply prepared soil and stake tall plants against wind. When sprouts at the base reach marble size, remove the growing tip (topping) to concentrate energy and speed maturation of the remaining sprouts. Harvest sprouts from the bottom of the stalk upward once they are 1–2 in across and tight. Flavor peaks after exposure to a hard frost.", "sources": ["general horticultural reference"]}')
