INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('butternut-squash','Butternut Squash','Cucurbita moschata','vegetable','cucurbit',4,10,60,95,85,110,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost; count back from first fall frost to ensure enough days to maturity.',3,10,36,60,12,18,72,120,'full','moderate','Sow 2–3 seeds 1 inch deep per hill in fertile, well-drained soil and thin to the strongest vine. Butternut is a long-season crop, so calculate the days to maturity against your first fall frost date before planting. The vines spread widely; allow 8–10 feet of run per plant. Harvest when the skin has turned uniformly tan and the stem dries out fully; cure for 10–14 days in a warm location before storing.','["general horticultural reference"]','{"slug": "butternut-squash", "common_name": "Butternut Squash", "scientific_name": "Cucurbita moschata", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 85, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost; count back from first fall frost to ensure enough days to maturity."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "moderate", "directions": "Sow 2–3 seeds 1 inch deep per hill in fertile, well-drained soil and thin to the strongest vine. Butternut is a long-season crop, so calculate the days to maturity against your first fall frost date before planting. The vines spread widely; allow 8–10 feet of run per plant. Harvest when the skin has turned uniformly tan and the stem dries out fully; cure for 10–14 days in a warm location before storing.", "sources": ["general horticultural reference"]}')
