INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cayenne-pepper','Cayenne Pepper','Capsicum annuum','vegetable','fruiting',8,14,75,85,70,80,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed.',4,11,14,18,24,36,14,18,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix, maintaining soil temperature above 75°F for prompt sprouting. Set transplants out once the garden is fully warm and side-dress with a balanced fertilizer once plants begin flowering. Thin-walled cayenne fruits dry exceptionally well; allow them to redden fully on the plant before harvesting for drying. String harvested peppers in a warm, airy location or use a dehydrator to preserve them.','["general horticultural reference"]','{"slug": "cayenne-pepper", "common_name": "Cayenne Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 8, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 70, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 14, "max": 18}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 14, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix, maintaining soil temperature above 75°F for prompt sprouting. Set transplants out once the garden is fully warm and side-dress with a balanced fertilizer once plants begin flowering. Thin-walled cayenne fruits dry exceptionally well; allow them to redden fully on the plant before harvesting for drying. String harvested peppers in a warm, airy location or use a dehydrator to preserve them.", "sources": ["general horticultural reference"]}')
