INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cucumber','Cucumber','Cucumis sativus','vegetable','cucurbit',3,10,60,95,50,70,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil temperature is at least 65°F.',3,11,12,18,12,60,18,48,'full','high','Sow seeds 1 inch deep in hills or rows once soil has warmed to at least 65°F. Cucumbers are high feeders; amend beds with compost and side-dress with nitrogen once vines begin running. Train vines onto a trellis to improve airflow and make harvest easier. Pick slicing types at 6–8 inches and pickling types at 2–4 inches to keep plants productive and prevent bitterness from over-ripe fruit.','["general horticultural reference"]','{"slug": "cucumber", "common_name": "Cucumber", "scientific_name": "Cucumis sativus", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 3, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil temperature is at least 65°F."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 60}, "spread_in": {"min": 18, "max": 48}, "sun": "full", "water": "high", "directions": "Sow seeds 1 inch deep in hills or rows once soil has warmed to at least 65°F. Cucumbers are high feeders; amend beds with compost and side-dress with nitrogen once vines begin running. Train vines onto a trellis to improve airflow and make harvest easier. Pick slicing types at 6–8 inches and pickling types at 2–4 inches to keep plants productive and prevent bitterness from over-ripe fruit.", "sources": ["general horticultural reference"]}')
