INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('delicata-squash','Delicata Squash','Cucurbita pepo','vegetable','cucurbit',4,10,60,95,80,100,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil is warm and settled.',3,10,24,36,12,18,48,84,'full','moderate','Sow seeds 1 inch deep in warm, fertile soil after last frost, placing 2–3 seeds per hill and thinning to one. Delicata is relatively compact for a winter squash, making it suitable for smaller gardens. The cream-and-green striped skin becomes creamy yellow with green stripes as it matures. Harvest when the background color shifts from white to creamy yellow and the skin resists puncture with a thumbnail.','["general horticultural reference"]','{"slug": "delicata-squash", "common_name": "Delicata Squash", "scientific_name": "Cucurbita pepo", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil is warm and settled."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 48, "max": 84}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 inch deep in warm, fertile soil after last frost, placing 2–3 seeds per hill and thinning to one. Delicata is relatively compact for a winter squash, making it suitable for smaller gardens. The cream-and-green striped skin becomes creamy yellow with green stripes as it matures. Harvest when the background color shifts from white to creamy yellow and the skin resists puncture with a thumbnail.", "sources": ["general horticultural reference"]}')
