INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('florence-fennel','Florence Fennel','Foeniculum vulgare var. azoricum','vegetable','stem',7,14,55,75,65,90,'seed','direct','cool','half-hardy','last_frost',-2,2,'Direct sow around last frost date; florence fennel resents transplanting and bolts readily under heat or day-length stress.',4,9,10,12,18,30,10,14,'full','moderate','Direct sow seed 1/4 in deep in well-drained, fertile soil and thin to 10–12 in; do not disturb roots once established. When the bulb-like base swells to tennis-ball size, mound soil or compost around it to blanch and sweeten the bulb. Harvest by cutting at or just below soil level when the bulb is 3–4 in across and firm. Choose bolt-resistant varieties for spring planting; fall crops generally produce better bulbs with less risk of premature bolting.','["general horticultural reference"]','{"slug": "florence-fennel", "common_name": "Florence Fennel", "scientific_name": "Foeniculum vulgare var. azoricum", "category": "vegetable", "subcategory": "stem", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 75}, "days_to_maturity": {"min": 65, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow around last frost date; florence fennel resents transplanting and bolts readily under heat or day-length stress."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 10, "max": 12}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "moderate", "directions": "Direct sow seed 1/4 in deep in well-drained, fertile soil and thin to 10–12 in; do not disturb roots once established. When the bulb-like base swells to tennis-ball size, mound soil or compost around it to blanch and sweeten the bulb. Harvest by cutting at or just below soil level when the bulb is 3–4 in across and firm. Choose bolt-resistant varieties for spring planting; fall crops generally produce better bulbs with less risk of premature bolting.", "sources": ["general horticultural reference"]}')
