INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('globe-artichoke','Globe Artichoke','Cynara scolymus','vegetable','perennial',10,14,65,80,85,100,'transplant','transplant','perennial','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; expose seedlings to cool temperatures (50°F) for 2 weeks before transplanting to vernalize and trigger bud set.',7,11,48,72,36,60,48,72,'full','moderate','Sow seed 1/4 in deep indoors and expose young plants to 2 weeks of 50°F nights to vernalize them for first-year bud production. Transplant into deeply amended, well-drained soil in a permanent location, as plants are long-lived when winters are mild enough. Harvest the central bud first, while bracts are tight and the stem snaps cleanly, then side buds as they develop. In zones 7–9, cut plants back to 12 in after harvest and mulch heavily for overwintering; divide clumps every 3–4 years to maintain vigor.','["general horticultural reference"]','{"slug": "globe-artichoke", "common_name": "Globe Artichoke", "scientific_name": "Cynara scolymus", "category": "vegetable", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; expose seedlings to cool temperatures (50°F) for 2 weeks before transplanting to vernalize and trigger bud set."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 48, "max": 72}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep indoors and expose young plants to 2 weeks of 50°F nights to vernalize them for first-year bud production. Transplant into deeply amended, well-drained soil in a permanent location, as plants are long-lived when winters are mild enough. Harvest the central bud first, while bracts are tight and the stem snaps cleanly, then side buds as they develop. In zones 7–9, cut plants back to 12 in after harvest and mulch heavily for overwintering; divide clumps every 3–4 years to maintain vigor.", "sources": ["general horticultural reference"]}')
