  VALUES ('green-onion','Green Onion (Scallion)','Allium fistulosum','vegetable','bulb',7,14,50,80,60,80,'seed','direct','cool','hardy','last_frost',-4,0,'Direct sow from 4 weeks before to the time of the last frost; succession sow every 3 weeks throughout the growing season.',3,11,1,2,12,18,1,2,'full','moderate','Sow seeds 1/4 in deep in bands 3–4 in wide rather than single rows to maximize bed productivity. Thin seedlings to 1–2 in apart; the thinnings are already usable as tiny scallions. Water steadily to keep growth rapid and tender; drought causes tough, hot-tasting stems. Pull bunching types when stems reach pencil width, or cut leaves an inch above the base and allow them to regrow for a second harvest.','["general horticultural reference"]','{"slug": "green-onion", "common_name": "Green Onion (Scallion)", "scientific_name": "Allium fistulosum", "category": "vegetable", "subcategory": "bulb", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow from 4 weeks before to the time of the last frost; succession sow every 3 weeks throughout the growing season."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 1, "max": 2}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in bands 3–4 in wide rather than single rows to maximize bed productivity. Thin seedlings to 1–2 in apart; the thinnings are already usable as tiny scallions. Water steadily to keep growth rapid and tender; drought causes tough, hot-tasting stems. Pull bunching types when stems reach pencil width, or cut leaves an inch above the base and allow them to regrow for a second harvest.", "sources": ["general horticultural reference"]}')
