  VALUES ('head-lettuce','Head Lettuce (Butterhead)','Lactuca sativa var. capitata','vegetable','leafy green',2,10,40,70,55,75,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Sow 2–4 weeks before last frost for spring crop; sow again in late summer for fall harvest.',2,11,8,12,8,12,8,12,'partial','moderate','Sow seed at 1/8 in depth and thin to 8–12 in once seedlings are 2 in tall; butterhead types form loose, tender heads with buttery inner leaves. Keep soil evenly moist and mulch to maintain cool root temperatures, as heat quickly triggers bolting. Harvest heads by cutting at the base when they feel moderately firm but before the center begins to elongate, which signals imminent bolting. Outer leaves can be removed as the head develops to stretch the harvest period over several weeks.','["general horticultural reference"]','{"slug": "head-lettuce", "common_name": "Head Lettuce (Butterhead)", "scientific_name": "Lactuca sativa var. capitata", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 2, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 70}, "days_to_maturity": {"min": 55, "max": 75}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow 2–4 weeks before last frost for spring crop; sow again in late summer for fall harvest."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 8, "max": 12}, "spread_in": {"min": 8, "max": 12}, "sun": "partial", "water": "moderate", "directions": "Sow seed at 1/8 in depth and thin to 8–12 in once seedlings are 2 in tall; butterhead types form loose, tender heads with buttery inner leaves. Keep soil evenly moist and mulch to maintain cool root temperatures, as heat quickly triggers bolting. Harvest heads by cutting at the base when they feel moderately firm but before the center begins to elongate, which signals imminent bolting. Outer leaves can be removed as the head develops to stretch the harvest period over several weeks.", "sources": ["general horticultural reference"]}')
