INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('honeydew-melon','Honeydew Melon','Cucumis melo var. inodorus','vegetable','cucurbit',3,10,70,90,80,100,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil is warm; in short-season climates, start indoors 3 weeks early.',5,11,24,36,12,18,72,120,'full','moderate','Sow seeds 1 inch deep in warm, well-drained soil enriched with compost, in hills of 4–5 seeds thinned to 2. Honeydew requires a longer, hotter season than cantaloupe; black plastic mulch is helpful in northern climates to boost soil warmth. Unlike cantaloupes, honeydews do not slip from the vine when ripe, so judge by skin color changing to creamy white, a waxy feel, and a sweet aroma from the blossom end. Cut fruits from the vine with a knife rather than pulling.','["general horticultural reference"]','{"slug": "honeydew-melon", "common_name": "Honeydew Melon", "scientific_name": "Cucumis melo var. inodorus", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 3, "max": 10}, "germination_soil_temp_f": {"min": 70, "max": 90}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil is warm; in short-season climates, start indoors 3 weeks early."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 inch deep in warm, well-drained soil enriched with compost, in hills of 4–5 seeds thinned to 2. Honeydew requires a longer, hotter season than cantaloupe; black plastic mulch is helpful in northern climates to boost soil warmth. Unlike cantaloupes, honeydews do not slip from the vine when ripe, so judge by skin color changing to creamy white, a waxy feel, and a sweet aroma from the blossom end. Cut fruits from the vine with a knife rather than pulling.", "sources": ["general horticultural reference"]}')
