  VALUES ('horseradish','Horseradish','Armoracia rusticana','vegetable','root',NULL,NULL,45,65,150,180,'transplant','division','perennial','hardy','last_frost',-4,-2,'Plant root cuttings 2–4 weeks before last frost; any root left in the soil will regenerate, so choose the site carefully as it becomes permanent.',3,9,18,24,24,36,18,24,'full','moderate','Plant 6–8 in root cuttings (thongs) at a 45-degree angle, 2–3 in deep, in deeply tilled, fertile soil; vertical planting produces rougher roots while angled planting encourages smoother, straight taproots. Horseradish is extremely vigorous and should be contained or given a dedicated bed where spreading is acceptable. Harvest main roots in autumn after the first hard frost triggers maximum heat and oil development. Save pencil-thick side roots to replant as next year''s cuttings.','["general horticultural reference"]','{"slug": "horseradish", "common_name": "Horseradish", "scientific_name": "Armoracia rusticana", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": 45, "max": 65}, "days_to_maturity": {"min": 150, "max": 180}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Plant root cuttings 2–4 weeks before last frost; any root left in the soil will regenerate, so choose the site carefully as it becomes permanent."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Plant 6–8 in root cuttings (thongs) at a 45-degree angle, 2–3 in deep, in deeply tilled, fertile soil; vertical planting produces rougher roots while angled planting encourages smoother, straight taproots. Horseradish is extremely vigorous and should be contained or given a dedicated bed where spreading is acceptable. Harvest main roots in autumn after the first hard frost triggers maximum heat and oil development. Save pencil-thick side roots to replant as next year''s cuttings.", "sources": ["general horticultural reference"]}')
