  VALUES ('jerusalem-artichoke','Jerusalem Artichoke','Helianthus tuberosus','vegetable','root',NULL,NULL,45,70,120,150,'transplant','tuber','perennial','hardy','last_frost',-4,-2,'Plant tubers 2–4 weeks before the last frost; Jerusalem artichokes are extremely cold-hardy and will regrow reliably each spring.',3,9,12,18,60,120,18,24,'full','low','Plant small, golf-ball-sized tubers 4 in deep in any well-drained soil; sunchokes tolerate poor, dry conditions and will crowd out weeds once established. Contain plantings with a buried barrier or dedicate a permanent bed, as any tuber left behind will regrow. Harvest tubers after the first hard frost sweetens them by converting inulin to sugars, digging with a fork and leaving the smallest tubers to perpetuate the planting. Store freshly dug tubers in the refrigerator as they do not keep well at room temperature.','["general horticultural reference"]','{"slug": "jerusalem-artichoke", "common_name": "Jerusalem Artichoke", "scientific_name": "Helianthus tuberosus", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": 45, "max": 70}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "transplant", "sow_method": "tuber", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Plant tubers 2–4 weeks before the last frost; Jerusalem artichokes are extremely cold-hardy and will regrow reliably each spring."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 60, "max": 120}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Plant small, golf-ball-sized tubers 4 in deep in any well-drained soil; sunchokes tolerate poor, dry conditions and will crowd out weeds once established. Contain plantings with a buried barrier or dedicate a permanent bed, as any tuber left behind will regrow. Harvest tubers after the first hard frost sweetens them by converting inulin to sugars, digging with a fork and leaving the smallest tubers to perpetuate the planting. Store freshly dug tubers in the refrigerator as they do not keep well at room temperature.", "sources": ["general horticultural reference"]}')
