INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('leaf-lettuce','Leaf Lettuce','Lactuca sativa var. crispa','vegetable','leafy green',2,10,40,75,30,55,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; succession sow every 2 weeks through spring, then again in fall.',2,11,6,10,6,12,6,10,'partial','moderate','Scatter or row-sow seed on the surface or barely cover with 1/8 in of soil, as light aids germination. Thin to 6–10 in and use thinnings as baby greens in salads to avoid waste. Harvest outer leaves continuously once plants are 4–6 in tall, or cut the entire plant an inch above the soil line for a cut-and-come-again harvest. Bolting in warm weather makes leaves bitter; provide shade cloth in late spring to extend the season.','["general horticultural reference"]','{"slug": "leaf-lettuce", "common_name": "Leaf Lettuce", "scientific_name": "Lactuca sativa var. crispa", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 2, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 30, "max": 55}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; succession sow every 2 weeks through spring, then again in fall."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 6, "max": 10}, "sun": "partial", "water": "moderate", "directions": "Scatter or row-sow seed on the surface or barely cover with 1/8 in of soil, as light aids germination. Thin to 6–10 in and use thinnings as baby greens in salads to avoid waste. Harvest outer leaves continuously once plants are 4–6 in tall, or cut the entire plant an inch above the soil line for a cut-and-come-again harvest. Bolting in warm weather makes leaves bitter; provide shade cloth in late spring to extend the season.", "sources": ["general horticultural reference"]}')
