INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('leek','Leek','Allium ampeloprasum var. porrum','vegetable','bulb',7,14,50,75,100,130,'transplant','indoor-start','cool','hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before the last frost; transplant seedlings into deep trenches after the last frost date.',3,9,6,9,18,30,4,6,'full','moderate','Sow seed 1/4 in deep indoors in flats and thin to 2 in; transplant pencil-thick seedlings into 6-in-deep trenches, dropping each plant into a dibber hole and filling with water rather than soil to encourage a long white shank. Gradually fill trenches and hill up soil around stems as they grow to blanch the shanks. Leeks tolerate hard frost and can be left in the ground well into winter for a late harvest. Dig as needed once shanks reach 1 in or more in diameter.','["general horticultural reference"]','{"slug": "leek", "common_name": "Leek", "scientific_name": "Allium ampeloprasum var. porrum", "category": "vegetable", "subcategory": "bulb", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 100, "max": 130}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before the last frost; transplant seedlings into deep trenches after the last frost date."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep indoors in flats and thin to 2 in; transplant pencil-thick seedlings into 6-in-deep trenches, dropping each plant into a dibber hole and filling with water rather than soil to encourage a long white shank. Gradually fill trenches and hill up soil around stems as they grow to blanch the shanks. Leeks tolerate hard frost and can be left in the ground well into winter for a late harvest. Dig as needed once shanks reach 1 in or more in diameter.", "sources": ["general horticultural reference"]}')
