INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('napa-cabbage','Napa Cabbage','Brassica rapa subsp. pekinensis','vegetable','brassica',4,7,50,85,50,80,'seed','direct','cool','half-hardy','first_frost',-10,-8,'For fall crop, direct sow 8–10 weeks before first frost; for spring, sow as soon as soil can be worked and harvest before summer heat triggers bolting.',4,9,12,18,12,18,12,18,'full','moderate','Direct sow 1/4 in deep in fertile, well-drained soil and thin to 12–18 in once seedlings are 3–4 in tall. Water regularly, as dry spells encourage premature bolting in warm weather. Fall planting generally produces better-quality heads with fewer pest problems. Harvest when heads feel firm and compact, cutting at the base before temperatures drop below 20°F.','["general horticultural reference"]','{"slug": "napa-cabbage", "common_name": "Napa Cabbage", "scientific_name": "Brassica rapa subsp. pekinensis", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 50, "max": 85}, "days_to_maturity": {"min": 50, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "For fall crop, direct sow 8–10 weeks before first frost; for spring, sow as soon as soil can be worked and harvest before summer heat triggers bolting."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Direct sow 1/4 in deep in fertile, well-drained soil and thin to 12–18 in once seedlings are 3–4 in tall. Water regularly, as dry spells encourage premature bolting in warm weather. Fall planting generally produces better-quality heads with fewer pest problems. Harvest when heads feel firm and compact, cutting at the base before temperatures drop below 20°F.", "sources": ["general horticultural reference"]}')
