INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('new-zealand-spinach','New Zealand Spinach','Tetragonia tetragonioides','vegetable','leafy green',10,21,60,75,55,70,'seed','direct','warm','tender','last_frost',0,2,'Direct sow after last frost when soil has warmed; soak seeds overnight to speed germination.',4,11,24,36,18,24,24,48,'full','low','Nick or soak seed for 24 hours before sowing 1/2 in deep after soil has warmed to at least 60°F; germination is slow and erratic without pre-soaking. Plants spread vigorously and fill space, so allow ample room of 2–3 ft per plant. Harvest by pinching stem tips of 3–4 in including the attached young leaves; regular harvesting keeps growth compact and productive through the entire warm season. Unlike true spinach, New Zealand spinach thrives in heat and is not bothered by long days, making it a valuable summer substitute.','["general horticultural reference"]','{"slug": "new-zealand-spinach", "common_name": "New Zealand Spinach", "scientific_name": "Tetragonia tetragonioides", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 75}, "days_to_maturity": {"min": 55, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow after last frost when soil has warmed; soak seeds overnight to speed germination."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "low", "directions": "Nick or soak seed for 24 hours before sowing 1/2 in deep after soil has warmed to at least 60°F; germination is slow and erratic without pre-soaking. Plants spread vigorously and fill space, so allow ample room of 2–3 ft per plant. Harvest by pinching stem tips of 3–4 in including the attached young leaves; regular harvesting keeps growth compact and productive through the entire warm season. Unlike true spinach, New Zealand spinach thrives in heat and is not bothered by long days, making it a valuable summer substitute.", "sources": ["general horticultural reference"]}')
