INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('okra','Okra','Abelmoschus esculentus','vegetable','fruiting',5,10,65,95,50,65,'seed','direct','warm','tender','last_frost',2,4,'Direct sow 2–4 weeks after last frost once soil temperature reaches at least 65°F; okra thrives in heat.',5,11,12,18,36,72,18,24,'full','moderate','Soak seeds in water for 12–24 hours before sowing 1 inch deep to soften the hard seed coat and speed germination. Plant in the hottest, sunniest spot available, as okra is a true heat-lover and grows slowly in cool conditions. Side-dress with a nitrogen-rich fertilizer when plants reach 12 inches tall to promote vigorous growth. Harvest pods every 2–3 days when they are 3–4 inches long and still tender; pods left to mature become tough and woody and reduce plant productivity.','["general horticultural reference"]','{"slug": "okra", "common_name": "Okra", "scientific_name": "Abelmoschus esculentus", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 50, "max": 65}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Direct sow 2–4 weeks after last frost once soil temperature reaches at least 65°F; okra thrives in heat."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Soak seeds in water for 12–24 hours before sowing 1 inch deep to soften the hard seed coat and speed germination. Plant in the hottest, sunniest spot available, as okra is a true heat-lover and grows slowly in cool conditions. Side-dress with a nitrogen-rich fertilizer when plants reach 12 inches tall to promote vigorous growth. Harvest pods every 2–3 days when they are 3–4 inches long and still tender; pods left to mature become tough and woody and reduce plant productivity.", "sources": ["general horticultural reference"]}')
