INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('parsnip','Parsnip','Pastinaca sativa','vegetable','root',14,28,45,65,100,130,'seed','direct','cool','hardy','last_frost',-4,-2,'Sow fresh seed 2–4 weeks before the last frost; parsnip seed has a very short viability window so always use seed from the current season.',2,9,3,6,12,18,4,6,'full','moderate','Sow 3 seeds per station 1/2 in deep in very deeply dug, stone-free soil and thin to the strongest seedling; long taproots will fork in compacted ground. Parsnip germination is notoriously slow and erratic — sowing radish seed in the same row acts as a quick-germinating row marker. Leave roots in the ground through autumn frosts, which convert starches to sugars for a sweeter harvest. Wear gloves when handling foliage in bright sun to avoid phototoxic sap burns.','["general horticultural reference"]','{"slug": "parsnip", "common_name": "Parsnip", "scientific_name": "Pastinaca sativa", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 45, "max": 65}, "days_to_maturity": {"min": 100, "max": 130}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow fresh seed 2–4 weeks before the last frost; parsnip seed has a very short viability window so always use seed from the current season."}, "usda_zones": {"min": 2, "max": 9}, "spacing_in": {"min": 3, "max": 6}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Sow 3 seeds per station 1/2 in deep in very deeply dug, stone-free soil and thin to the strongest seedling; long taproots will fork in compacted ground. Parsnip germination is notoriously slow and erratic — sowing radish seed in the same row acts as a quick-germinating row marker. Leave roots in the ground through autumn frosts, which convert starches to sugars for a sweeter harvest. Wear gloves when handling foliage in bright sun to avoid phototoxic sap burns.", "sources": ["general horticultural reference"]}')
