INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pattypan-squash','Pattypan Squash','Cucurbita pepo','vegetable','cucurbit',4,10,60,95,50,65,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil temperature is at least 65°F.',3,10,24,36,18,30,24,36,'full','moderate','Sow seeds 1 inch deep in warm, fertile soil in hills of 2–3 seeds, thinning to the strongest plant. Consistent moisture at the root zone keeps the bush compact and productive throughout the season. Pattypan''s distinctive flying-saucer shape makes sizing easy. Harvest when fruits are 2–3 inches across for the most tender flesh; over-mature fruits become tough and seedy.','["general horticultural reference"]','{"slug": "pattypan-squash", "common_name": "Pattypan Squash", "scientific_name": "Cucurbita pepo", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 50, "max": 65}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil temperature is at least 65°F."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 inch deep in warm, fertile soil in hills of 2–3 seeds, thinning to the strongest plant. Consistent moisture at the root zone keeps the bush compact and productive throughout the season. Pattypan''s distinctive flying-saucer shape makes sizing easy. Harvest when fruits are 2–3 inches across for the most tender flesh; over-mature fruits become tough and seedy.", "sources": ["general horticultural reference"]}')
