INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('poblano','Poblano Pepper','Capsicum annuum','vegetable','fruiting',8,14,75,85,65,80,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 2 weeks after frost danger has passed.',4,11,18,24,24,48,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix and provide bottom heat around 80°F to speed germination. Transplant to fertile, well-drained soil once nights are consistently above 55°F. Water deeply but infrequently to encourage deep rooting and reduce disease pressure. Harvest dark green fruits at 4–5 inches long for fresh use, or allow to turn red and dry them for ancho chiles.','["general horticultural reference"]','{"slug": "poblano", "common_name": "Poblano Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 8, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 65, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 2 weeks after frost danger has passed."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix and provide bottom heat around 80°F to speed germination. Transplant to fertile, well-drained soil once nights are consistently above 55°F. Water deeply but infrequently to encourage deep rooting and reduce disease pressure. Harvest dark green fruits at 4–5 inches long for fresh use, or allow to turn red and dry them for ancho chiles.", "sources": ["general horticultural reference"]}')
