INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('potato','Potato','Solanum tuberosum','vegetable','root',NULL,NULL,45,70,60,120,'transplant','tuber','cool','half-hardy','last_frost',-4,-2,'Plant seed pieces 2–4 weeks before last frost when soil reaches 45°F; in warm climates a second planting is made in late summer for a fall crop.',3,10,10,14,18,30,18,24,'full','moderate','Plant certified seed potatoes cut to egg-sized pieces (each with 1–2 eyes) 4 in deep in trenches spaced 30 in apart. Hill soil up around the stems as they grow, keeping tubers covered to prevent greening from light exposure. Water consistently and watch for late blight in humid weather — infected foliage should be removed promptly to protect tubers. Harvest new potatoes when plants flower, or cure full-season types for a week at room temperature before long-term storage.','["general horticultural reference"]','{"slug": "potato", "common_name": "Potato", "scientific_name": "Solanum tuberosum", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": 45, "max": 70}, "days_to_maturity": {"min": 60, "max": 120}, "maturity_from": "transplant", "sow_method": "tuber", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Plant seed pieces 2–4 weeks before last frost when soil reaches 45°F; in warm climates a second planting is made in late summer for a fall crop."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 10, "max": 14}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Plant certified seed potatoes cut to egg-sized pieces (each with 1–2 eyes) 4 in deep in trenches spaced 30 in apart. Hill soil up around the stems as they grow, keeping tubers covered to prevent greening from light exposure. Water consistently and watch for late blight in humid weather — infected foliage should be removed promptly to protect tubers. Harvest new potatoes when plants flower, or cure full-season types for a week at room temperature before long-term storage.", "sources": ["general horticultural reference"]}')
