INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('radicchio','Radicchio','Cichorium intybus var. foliosum','vegetable','leafy green',5,10,50,75,80,100,'seed','direct','cool','hardy','first_frost',-14,-10,'For tight, colorful heads, sow in midsummer so radicchio heads up during cool fall weather, 10–14 weeks before first frost.',4,10,10,14,8,12,10,14,'full','moderate','Sow seed 1/4 in deep and thin to 10–14 in; radicchio produces loose, green summer foliage before forming its characteristic red and white tight head as days shorten and temperatures fall. Cut back summer foliage to about 1 in when plants look tired and cool temperatures arrive; new heads will form from the crown within 3–4 weeks. Harvest compact heads by cutting at the base once they feel firm and the color is deep burgundy. Hard frost may damage outer leaves but the inner head often survives.','["general horticultural reference"]','{"slug": "radicchio", "common_name": "Radicchio", "scientific_name": "Cichorium intybus var. foliosum", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -14, "max": -10}, "note": "For tight, colorful heads, sow in midsummer so radicchio heads up during cool fall weather, 10–14 weeks before first frost."}, "usda_zones": {"min": 4, "max": 10}, "spacing_in": {"min": 10, "max": 14}, "height_in": {"min": 8, "max": 12}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep and thin to 10–14 in; radicchio produces loose, green summer foliage before forming its characteristic red and white tight head as days shorten and temperatures fall. Cut back summer foliage to about 1 in when plants look tired and cool temperatures arrive; new heads will form from the crown within 3–4 weeks. Harvest compact heads by cutting at the base once they feel firm and the color is deep burgundy. Hard frost may damage outer leaves but the inner head often survives.", "sources": ["general horticultural reference"]}')
