INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('radish','Radish','Raphanus sativus','vegetable','root',3,7,45,85,22,35,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Sow 2–4 weeks before last frost; succession sow every 10 days for continuous harvest, stopping when summer heat sets in.',2,11,2,3,6,12,2,3,'full','moderate','Sow seed 1/2 in deep in cool, well-drained soil at 10-day intervals for a steady supply. Radishes bolt quickly in heat or long days, so spring and fall are the prime windows. Thin to 2 in as soon as seedlings are up to prevent overcrowding, which causes lanky tops and small or misshapen roots. Pull spring types at 3/4 to 1 in diameter before they become hot and pithy.','["general horticultural reference"]','{"slug": "radish", "common_name": "Radish", "scientific_name": "Raphanus sativus", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 22, "max": 35}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow 2–4 weeks before last frost; succession sow every 10 days for continuous harvest, stopping when summer heat sets in."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 2, "max": 3}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 2, "max": 3}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/2 in deep in cool, well-drained soil at 10-day intervals for a steady supply. Radishes bolt quickly in heat or long days, so spring and fall are the prime windows. Thin to 2 in as soon as seedlings are up to prevent overcrowding, which causes lanky tops and small or misshapen roots. Pull spring types at 3/4 to 1 in diameter before they become hot and pithy.", "sources": ["general horticultural reference"]}')
