  VALUES ('rhubarb','Rhubarb','Rheum x hybridum','vegetable','perennial',14,21,50,70,365,730,'transplant','division','perennial','hardy','soil_workable',0,4,'Plant divisions as soon as soil is workable in early spring; each division should have at least one large bud.',3,8,36,48,24,48,36,48,'full','moderate','Plant root divisions 3–4 in deep in deeply dug, compost-enriched soil, setting buds just at the soil surface. Do not harvest any stalks in the first year, and take only a few in year two so the crown can establish a deep root system. From year three onward, harvest stalks when they are 12–18 in long and 3/4 in thick by pulling and twisting at the base; remove any flower stalks that appear immediately to prevent weakening the crown. Note that only the stalks are edible—the leaves contain high concentrations of oxalic acid and are toxic.','["general horticultural reference"]','{"slug": "rhubarb", "common_name": "Rhubarb", "scientific_name": "Rheum x hybridum", "category": "vegetable", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions as soon as soil is workable in early spring; each division should have at least one large bud."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 36, "max": 48}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 36, "max": 48}, "sun": "full", "water": "moderate", "directions": "Plant root divisions 3–4 in deep in deeply dug, compost-enriched soil, setting buds just at the soil surface. Do not harvest any stalks in the first year, and take only a few in year two so the crown can establish a deep root system. From year three onward, harvest stalks when they are 12–18 in long and 3/4 in thick by pulling and twisting at the base; remove any flower stalks that appear immediately to prevent weakening the crown. Note that only the stalks are edible—the leaves contain high concentrations of oxalic acid and are toxic.", "sources": ["general horticultural reference"]}')
