INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('romaine-lettuce','Romaine Lettuce','Lactuca sativa var. longifolia','vegetable','leafy green',2,10,40,75,60,80,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow or transplant 2–4 weeks before last frost; for fall, sow 8–10 weeks before first frost.',2,11,8,12,8,18,8,12,'partial','moderate','Sow seed at 1/8 in depth in cool soil and thin to 8–12 in; romaine forms an upright, elongated head that needs slightly more space than loose-leaf types. Keep soil evenly moist to prevent tip burn, which appears as brown leaf edges due to calcium deficiency from moisture stress. Harvest by cutting the whole head at soil level when it is 8–10 in tall and the inner leaves feel firm. Outer leaves can be removed individually as the head develops to extend the harvest period.','["general horticultural reference"]','{"slug": "romaine-lettuce", "common_name": "Romaine Lettuce", "scientific_name": "Lactuca sativa var. longifolia", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 2, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow or transplant 2–4 weeks before last frost; for fall, sow 8–10 weeks before first frost."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 8, "max": 18}, "spread_in": {"min": 8, "max": 12}, "sun": "partial", "water": "moderate", "directions": "Sow seed at 1/8 in depth in cool soil and thin to 8–12 in; romaine forms an upright, elongated head that needs slightly more space than loose-leaf types. Keep soil evenly moist to prevent tip burn, which appears as brown leaf edges due to calcium deficiency from moisture stress. Harvest by cutting the whole head at soil level when it is 8–10 in tall and the inner leaves feel firm. Outer leaves can be removed individually as the head develops to extend the harvest period.", "sources": ["general horticultural reference"]}')
