INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('romanesco','Romanesco','Brassica oleracea var. botrytis','vegetable','brassica',5,10,50,80,75,100,'transplant','indoor-start','cool','half-hardy','first_frost',-20,-16,'Start indoors and transplant so heads mature in cool fall weather; aim to transplant about 16 weeks before first frost.',3,10,18,24,18,30,18,24,'full','moderate','Sow seed 1/4 in deep indoors 6–8 weeks before transplant date; romanesco demands consistent temperatures between 60–65°F during head formation or it fails to produce proper fractal spirals. Transplant into deeply amended soil and water evenly throughout the season, as any moisture stress affects head quality. Harvest the single central head when the spiral turrets are sharp and well-defined but before any yellowing begins. Unlike broccoli, romanesco rarely produces usable side shoots after the main head is cut.','["general horticultural reference"]','{"slug": "romanesco", "common_name": "Romanesco", "scientific_name": "Brassica oleracea var. botrytis", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -20, "max": -16}, "note": "Start indoors and transplant so heads mature in cool fall weather; aim to transplant about 16 weeks before first frost."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep indoors 6–8 weeks before transplant date; romanesco demands consistent temperatures between 60–65°F during head formation or it fails to produce proper fractal spirals. Transplant into deeply amended soil and water evenly throughout the season, as any moisture stress affects head quality. Harvest the single central head when the spiral turrets are sharp and well-defined but before any yellowing begins. Unlike broccoli, romanesco rarely produces usable side shoots after the main head is cut.", "sources": ["general horticultural reference"]}')
