INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('runner-bean','Runner Bean','Phaseolus coccineus','vegetable','legume',8,14,54,75,60,80,'seed','direct','warm','tender','last_frost',0,2,'Sow around or just after last frost; runner beans prefer cooler summers than common beans and will drop flowers in intense heat.',4,11,6,9,72,120,12,18,'full','moderate','Sow seeds 2 in deep at the base of a robust trellis or obelisk at least 6 ft tall; runner beans are vigorous climbers and will overwhelm light supports. The scarlet flowers attract hummingbirds and are themselves edible. Pick pods frequently at 6–8 in before they become stringy; pods left to mature inhibit further flowering. In frost-free climates, tuberous roots can be overwintered and will regrow the following spring.','["general horticultural reference"]','{"slug": "runner-bean", "common_name": "Runner Bean", "scientific_name": "Phaseolus coccineus", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 8, "max": 14}, "germination_soil_temp_f": {"min": 54, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Sow around or just after last frost; runner beans prefer cooler summers than common beans and will drop flowers in intense heat."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 72, "max": 120}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 2 in deep at the base of a robust trellis or obelisk at least 6 ft tall; runner beans are vigorous climbers and will overwhelm light supports. The scarlet flowers attract hummingbirds and are themselves edible. Pick pods frequently at 6–8 in before they become stringy; pods left to mature inhibit further flowering. In frost-free climates, tuberous roots can be overwintered and will regrow the following spring.", "sources": ["general horticultural reference"]}')
