INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('rutabaga','Rutabaga','Brassica napus var. napobrassica','vegetable','root',5,12,45,85,85,100,'seed','direct','cool','hardy','first_frost',-14,-12,'Sow 12–14 weeks before the expected first autumn frost so roots mature in cool weather.',2,10,6,8,10,18,6,10,'full','moderate','Sow seeds 1/2 in deep in fertile, well-drained soil; rutabagas need more time and space than turnips to produce their large storage roots. Thin to 6–8 in once seedlings are established and keep soil evenly moist to prevent splitting. Flavor is significantly improved by frost, so aim to leave roots in the ground until after the first hard freeze. Harvest before the ground freezes solid and store in a cool, humid root cellar for several months.','["general horticultural reference"]','{"slug": "rutabaga", "common_name": "Rutabaga", "scientific_name": "Brassica napus var. napobrassica", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 5, "max": 12}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -14, "max": -12}, "note": "Sow 12–14 weeks before the expected first autumn frost so roots mature in cool weather."}, "usda_zones": {"min": 2, "max": 10}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 10, "max": 18}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/2 in deep in fertile, well-drained soil; rutabagas need more time and space than turnips to produce their large storage roots. Thin to 6–8 in once seedlings are established and keep soil evenly moist to prevent splitting. Flavor is significantly improved by frost, so aim to leave roots in the ground until after the first hard freeze. Harvest before the ground freezes solid and store in a cool, humid root cellar for several months.", "sources": ["general horticultural reference"]}')
