INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('serrano-pepper','Serrano Pepper','Capsicum annuum','vegetable','fruiting',8,14,75,85,70,85,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed.',4,11,14,18,18,36,14,18,'full','moderate','Sow seeds 1/4 inch deep in warm, moist starting mix and provide consistent warmth around 80°F for best germination results. Transplant into well-drained, fertile garden soil after the last frost, spacing plants to allow good airflow. Serranos are productive plants that benefit from light fertilization mid-season. Harvest small green fruits at 1–2 inches long for peak heat and crunch, or let them ripen to red for a slightly fruity flavor.','["general horticultural reference"]','{"slug": "serrano-pepper", "common_name": "Serrano Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 8, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 70, "max": 85}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 14, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 14, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm, moist starting mix and provide consistent warmth around 80°F for best germination results. Transplant into well-drained, fertile garden soil after the last frost, spacing plants to allow good airflow. Serranos are productive plants that benefit from light fertilization mid-season. Harvest small green fruits at 1–2 inches long for peak heat and crunch, or let them ripen to red for a slightly fruity flavor.", "sources": ["general horticultural reference"]}')
