  VALUES ('shallot','Shallot','Allium cepa var. aggregatum','vegetable','bulb',NULL,NULL,50,75,90,120,'transplant','bulb','cool','hardy','last_frost',-4,-2,'Plant cloves 2–4 weeks before last frost in spring; in mild climates, an autumn planting produces larger bulbs.',3,10,6,8,12,18,4,6,'full','moderate','Separate shallot clusters into individual cloves and plant each with the tip just at or slightly above the soil surface, 1 in deep, in fertile, well-drained soil. Each clove multiplies into a cluster of 6–12 new bulbs by season''s end, so generous spacing pays off. Harvest when most of the green tops have toppled and turned papery. Dry clusters on screens in good airflow for 2–3 weeks and store in a cool, airy spot; well-cured shallots keep for 6 months or more.','["general horticultural reference"]','{"slug": "shallot", "common_name": "Shallot", "scientific_name": "Allium cepa var. aggregatum", "category": "vegetable", "subcategory": "bulb", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Plant cloves 2–4 weeks before last frost in spring; in mild climates, an autumn planting produces larger bulbs."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Separate shallot clusters into individual cloves and plant each with the tip just at or slightly above the soil surface, 1 in deep, in fertile, well-drained soil. Each clove multiplies into a cluster of 6–12 new bulbs by season''s end, so generous spacing pays off. Harvest when most of the green tops have toppled and turned papery. Dry clusters on screens in good airflow for 2–3 weeks and store in a cool, airy spot; well-cured shallots keep for 6 months or more.", "sources": ["general horticultural reference"]}')
