  VALUES ('shelling-pea','Shelling Pea','Pisum sativum','vegetable','legume',6,15,40,75,60,80,'seed','direct','cool','hardy','last_frost',-6,-4,'Sow as early as the ground is workable, typically 4–6 weeks before the last frost date.',2,11,2,4,24,48,6,12,'full','moderate','Sow seeds 1 in deep in rows 18 in apart and provide support for tall types. Consistent moisture from flowering through pod fill is critical; drought during this window sharply reduces yield. Harvest when pods are well rounded and the peas inside feel firm through the pod wall; sugar converts rapidly to starch after picking, so chill or eat immediately. Shell and freeze any surplus the same day for best sweetness.','["general horticultural reference"]','{"slug": "shelling-pea", "common_name": "Shelling Pea", "scientific_name": "Pisum sativum", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 6, "max": 15}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Sow as early as the ground is workable, typically 4–6 weeks before the last frost date."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 in deep in rows 18 in apart and provide support for tall types. Consistent moisture from flowering through pod fill is critical; drought during this window sharply reduces yield. Harvest when pods are well rounded and the peas inside feel firm through the pod wall; sugar converts rapidly to starch after picking, so chill or eat immediately. Shell and freeze any surplus the same day for best sweetness.", "sources": ["general horticultural reference"]}')
