INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('snap-pea','Snap Pea','Pisum sativum var. macrocarpon','vegetable','legume',6,15,40,75,58,70,'seed','direct','cool','hardy','last_frost',-6,-4,'Direct sow 4–6 weeks before last frost; a fall planting 8 weeks before first frost is equally productive in many climates.',2,11,2,4,24,60,6,12,'full','moderate','Sow seed 1 in deep as soon as the ground can be worked and provide twiggy brush or mesh netting for vines to climb. Pre-soaking seeds overnight can improve germination in cold soil. Harvest when pods are plump, fully filled, and glossy; snap peas pass their peak quickly in warm weather. Powdery mildew is common late in the season — choose resistant varieties when available.','["general horticultural reference"]','{"slug": "snap-pea", "common_name": "Snap Pea", "scientific_name": "Pisum sativum var. macrocarpon", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 6, "max": 15}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 58, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow 4–6 weeks before last frost; a fall planting 8 weeks before first frost is equally productive in many climates."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seed 1 in deep as soon as the ground can be worked and provide twiggy brush or mesh netting for vines to climb. Pre-soaking seeds overnight can improve germination in cold soil. Harvest when pods are plump, fully filled, and glossy; snap peas pass their peak quickly in warm weather. Powdery mildew is common late in the season — choose resistant varieties when available.", "sources": ["general horticultural reference"]}')
