INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('snow-pea','Snow Pea','Pisum sativum var. saccharatum','vegetable','legume',6,15,40,75,55,70,'seed','direct','cool','hardy','last_frost',-6,-4,'Sow 4–6 weeks before the last spring frost or in early autumn; cool weather produces the crispest, sweetest pods.',2,11,2,4,24,60,6,12,'full','moderate','Press seeds 1 in deep into cool, well-drained soil and erect support netting before the vines need it. Snow peas are harvested when pods are flat, bright green, and the seeds inside are barely visible; even slight bulging means the pod is overripe for stir-fry use. Keep pods picked daily during peak production to sustain cropping. Avoid high-nitrogen fertilizers, which produce lush foliage at the expense of pods.','["general horticultural reference"]','{"slug": "snow-pea", "common_name": "Snow Pea", "scientific_name": "Pisum sativum var. saccharatum", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 6, "max": 15}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 55, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Sow 4–6 weeks before the last spring frost or in early autumn; cool weather produces the crispest, sweetest pods."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Press seeds 1 in deep into cool, well-drained soil and erect support netting before the vines need it. Snow peas are harvested when pods are flat, bright green, and the seeds inside are barely visible; even slight bulging means the pod is overripe for stir-fry use. Keep pods picked daily during peak production to sustain cropping. Avoid high-nitrogen fertilizers, which produce lush foliage at the expense of pods.", "sources": ["general horticultural reference"]}')
