INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('spinach','Spinach','Spinacia oleracea','vegetable','leafy green',7,14,35,70,37,50,'seed','direct','cool','hardy','last_frost',-6,-4,'Direct sow 4–6 weeks before last frost in spring; also sow in fall 6–8 weeks before first frost for overwintering where winters are mild.',2,9,3,6,6,12,6,10,'partial','moderate','Sow seed 1/2 in deep in fertile, slightly alkaline soil and keep evenly moist; germination is slow in warm soil above 70°F. Thin to 3–6 in and fertilize with nitrogen to encourage lush, dark-green growth. Begin harvesting outer leaves once plants have 6–8 leaves, or cut the whole plant about 1 in above the crown for regrowth. Bolting is triggered by long days and heat; choose slow-bolt varieties for extended spring harvests.','["general horticultural reference"]','{"slug": "spinach", "common_name": "Spinach", "scientific_name": "Spinacia oleracea", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 35, "max": 70}, "days_to_maturity": {"min": 37, "max": 50}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow 4–6 weeks before last frost in spring; also sow in fall 6–8 weeks before first frost for overwintering where winters are mild."}, "usda_zones": {"min": 2, "max": 9}, "spacing_in": {"min": 3, "max": 6}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 6, "max": 10}, "sun": "partial", "water": "moderate", "directions": "Sow seed 1/2 in deep in fertile, slightly alkaline soil and keep evenly moist; germination is slow in warm soil above 70°F. Thin to 3–6 in and fertilize with nitrogen to encourage lush, dark-green growth. Begin harvesting outer leaves once plants have 6–8 leaves, or cut the whole plant about 1 in above the crown for regrowth. Bolting is triggered by long days and heat; choose slow-bolt varieties for extended spring harvests.", "sources": ["general horticultural reference"]}')
