INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sweet-corn','Sweet Corn','Zea mays var. saccharata','vegetable','grain',5,10,55,95,60,90,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at last frost date once soil temperature reaches at least 55°F; sow in blocks of at least 4 rows for good pollination.',3,11,9,12,60,96,12,18,'full','moderate','Sow seeds 1–2 inches deep in blocks rather than single rows to ensure adequate wind pollination; block width should be at least 4 rows. Side-dress with nitrogen fertilizer when plants reach knee-height and again at tasseling to support high yields. Silks turn brown and dry about 20 days after they appear, signaling readiness; peel back the husk and pierce a kernel to check for milky juice as the ripeness test. Eat or preserve immediately after harvest for maximum sweetness, especially with modern supersweet varieties.','["general horticultural reference"]','{"slug": "sweet-corn", "common_name": "Sweet Corn", "scientific_name": "Zea mays var. saccharata", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 55, "max": 95}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at last frost date once soil temperature reaches at least 55°F; sow in blocks of at least 4 rows for good pollination."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 60, "max": 96}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1–2 inches deep in blocks rather than single rows to ensure adequate wind pollination; block width should be at least 4 rows. Side-dress with nitrogen fertilizer when plants reach knee-height and again at tasseling to support high yields. Silks turn brown and dry about 20 days after they appear, signaling readiness; peel back the husk and pierce a kernel to check for milky juice as the ripeness test. Eat or preserve immediately after harvest for maximum sweetness, especially with modern supersweet varieties.", "sources": ["general horticultural reference"]}')
