INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sweet-potato','Sweet Potato','Ipomoea batatas','vegetable','root',NULL,NULL,65,85,90,120,'transplant','transplant','warm','tender','last_frost',2,4,'Set out slips 2–4 weeks after last frost when soil is reliably warm; sweet potato vines are extremely cold-sensitive.',5,11,12,18,12,18,36,60,'full','moderate','Plant rooted slips 4 in deep in well-drained, loose soil on raised ridges or mounded rows to warm quickly; slips are propagated by sprouting cured roots in a warm, humid space 6–8 weeks before planting out. Resist fertilizing heavily with nitrogen, which favors vines over tubers. Harvest before the first frost by carefully lifting roots with a broad fork; any nicks will rot in storage. Cure freshly dug sweet potatoes at 85–90°F with high humidity for 10 days before storing at 55–60°F.','["general horticultural reference"]','{"slug": "sweet-potato", "common_name": "Sweet Potato", "scientific_name": "Ipomoea batatas", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "transplant", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Set out slips 2–4 weeks after last frost when soil is reliably warm; sweet potato vines are extremely cold-sensitive."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "moderate", "directions": "Plant rooted slips 4 in deep in well-drained, loose soil on raised ridges or mounded rows to warm quickly; slips are propagated by sprouting cured roots in a warm, humid space 6–8 weeks before planting out. Resist fertilizing heavily with nitrogen, which favors vines over tubers. Harvest before the first frost by carefully lifting roots with a broad fork; any nicks will rot in storage. Cure freshly dug sweet potatoes at 85–90°F with high humidity for 10 days before storing at 55–60°F.", "sources": ["general horticultural reference"]}')
