  VALUES ('swiss-chard','Swiss Chard','Beta vulgaris subsp. vulgaris','vegetable','leafy green',7,14,50,85,50,60,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost in spring; also sow in late summer for a fall crop.',3,10,6,12,12,24,12,18,'full','moderate','Each chard seed is actually a cluster of seeds, so thin aggressively to 6–12 in once seedlings establish; sow 1/2 in deep. Swiss chard tolerates more summer heat than spinach, making it a valuable warm-gap green as long as irrigation is consistent. Harvest outer stalks when 8–10 in long, cutting cleanly at the base without disturbing the crown. Plants will produce continuously until heavy frost; mulching extends the season into early winter in temperate climates.','["general horticultural reference"]','{"slug": "swiss-chard", "common_name": "Swiss Chard", "scientific_name": "Beta vulgaris subsp. vulgaris", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 85}, "days_to_maturity": {"min": 50, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost in spring; also sow in late summer for a fall crop."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Each chard seed is actually a cluster of seeds, so thin aggressively to 6–12 in once seedlings establish; sow 1/2 in deep. Swiss chard tolerates more summer heat than spinach, making it a valuable warm-gap green as long as irrigation is consistent. Harvest outer stalks when 8–10 in long, cutting cleanly at the base without disturbing the crown. Plants will produce continuously until heavy frost; mulching extends the season into early winter in temperate climates.", "sources": ["general horticultural reference"]}')
