INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tomatillo','Tomatillo','Physalis philadelphica','vegetable','fruiting',7,14,70,85,60,80,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant 1–2 weeks after frost danger has passed.',4,11,24,36,36,60,24,36,'full','moderate','Sow seeds 1/4 inch deep in warm, moist starting mix about 6–8 weeks before transplanting. Plant at least two plants for cross-pollination, which is necessary for fruit set. Allow the husk to fully enclose the fruit and turn papery before harvesting. Fruit is ready when it fills the husk and the husk begins to split.','["general horticultural reference"]','{"slug": "tomatillo", "common_name": "Tomatillo", "scientific_name": "Physalis philadelphica", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant 1–2 weeks after frost danger has passed."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm, moist starting mix about 6–8 weeks before transplanting. Plant at least two plants for cross-pollination, which is necessary for fruit set. Allow the husk to fully enclose the fruit and turn papery before harvesting. Fruit is ready when it fills the husk and the husk begins to split.", "sources": ["general horticultural reference"]}')
